import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    CheckCircleIcon,
    TrashIcon,
    CheckBadgeIcon,
    FloppyDiskIcon,
    PhotoIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction, MatchResult } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted';
}

type ViewMode = 'original' | 'text';

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<Record<number, TreatedRow>>({});
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isLearning, setIsLearning] = useState(false);
    const [isInitialInfering, setIsInitialInfering] = useState(false);
    const [viewMode, setViewMode] = useState<ViewMode>('original');
    const [currentFileUrl, setCurrentFileUrl] = useState<string | null>(null);
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    // Gerenciamento do Arquivo e Inferência
    useEffect(() => {
        if (!initialFile) return;

        // 1. Processamento de Texto para a Tabela e IA
        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = ';';
            const firstDataLine = lines.find(l => l.includes(';') || l.includes(',') || l.includes('\t')) || lines[0];
            if (firstDataLine.includes('\t')) delimiter = '\t';
            else if (!firstDataLine.includes(';') && firstDataLine.includes(',')) delimiter = ',';

            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initialTreated: Record<number, TreatedRow> = {};
            parsed.forEach((_, idx) => {
                initialTreated[idx] = {
                    date: '',
                    name: '[processando...]',
                    amount: '0,00',
                    status: 'unrecognized'
                };
            });
            setTreatedRows(initialTreated);
            triggerInitialInference(parsed);
        }

        // 2. Carregamento do Visualizador Real
        const fileObj = initialFile.rawFile;
        if (fileObj && (fileObj instanceof Blob || fileObj instanceof File || (fileObj.size && fileObj.type))) {
            const safeBlob = fileObj instanceof Blob ? fileObj : new Blob([fileObj], { type: fileObj.type });

            if (isPdf) {
                const blobUrl = URL.createObjectURL(safeBlob);
                setCurrentFileUrl(blobUrl);
                return () => URL.revokeObjectURL(blobUrl);
            } else if (isExcel) {
                const reader = new FileReader();
                reader.onload = (e) => {
                    try {
                        const data = new Uint8Array(e.target?.result as ArrayBuffer);
                        const workbook = XLSX.read(data, { type: 'array' });
                        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                        const html = XLSX.utils.sheet_to_html(firstSheet, { editable: false });
                        setExcelHtml(html);
                    } catch (err) {
                        console.error("Erro ao converter Excel para HTML", err);
                    }
                };
                reader.readAsArrayBuffer(safeBlob);
            }
        }
    }, [initialFile, isPdf, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        setIsInitialInfering(true);
        try {
            const cleanSample = rows
                .map((r, i) => ({ row: r.map(c => c.trim()), index: i }))
                .filter(item => item.row.some(c => c.length > 0))
                .slice(0, 60);

            const initialGuess = await performInitialInference(cleanSample.map(s => s.row));

            setTreatedRows(prev => {
                const newTreated = { ...prev };
                initialGuess.forEach((res: any, idx: number) => {
                    const originalIdx = cleanSample[idx]?.index;
                    if (originalIdx !== undefined) {
                        let status: TreatedRow['status'] = 'inferred';
                        if (res.name.includes('[suspeito]')) status = 'suspect';

                        newTreated[originalIdx] = {
                            date: res.date,
                            name: res.name.replace('[suspeito] ', ''),
                            amount: res.amount,
                            status: status
                        };
                    }
                });
                return newTreated;
            });
        } catch (e) {
            console.error("Erro na inferência IA:", e);
        } finally {
            setIsInitialInfering(false);
        }
    };

    const deduceMapping = () => {
        const manualEntries = (Object.entries(treatedRows) as [string, TreatedRow][])
            .filter(([_, data]) => data.status === 'manual');

        if (manualEntries.length === 0) return { date: 0, desc: 1, amount: 2 };

        const [idx, treated] = manualEntries[0];
        const original = rawRows[parseInt(idx)];

        const dateIdx = original.findIndex(cell => cell.includes(treated.date.split('-')[2] || '---'));
        const amountIdx = original.findIndex(cell => cell.replace(/[^\d]/g, '').includes(treated.amount.replace(/[^\d]/g, '').substring(0, 3)));
        const descIdx = original.findIndex((cell, i) => i !== dateIdx && i !== amountIdx && cell.trim().length > 2);

        return {
            date: dateIdx !== -1 ? dateIdx : 0,
            desc: descIdx !== -1 ? descIdx : 1,
            amount: amountIdx !== -1 ? amountIdx : 2
        };
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);

        try {
            const fingerprint = generateFingerprint(initialFile.content);
            const mapping = deduceMapping();

            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName.split('.')[0]}`,
                    user_id: user.id,
                    version: 1,
                    lineage_id: `lin-${Date.now()}`,
                    is_active: true,
                    fingerprint: fingerprint,
                    mapping: {
                        dateColumnIndex: mapping.date,
                        descriptionColumnIndex: mapping.desc,
                        amountColumnIndex: mapping.amount,
                        skipRowsStart: 1,
                        skipRowsEnd: 0,
                        decimalSeparator: ',',
                        thousandsSeparator: '.'
                    },
                    parsingRules: {
                        ignoredKeywords: customIgnoreKeywords,
                        rowFilters: (Object.values(treatedRows) as TreatedRow[])
                            .filter(r => r.status === 'deleted')
                            .map(r => r.name)
                    }
                };

                await modelService.saveModel(modelData);
                await fetchModels(); 
                showToast("Inteligência de layout salva!", "success");
            }
            onClose();
        } catch (e) {
            showToast("Erro ao processar modelo.", "error");
        } finally {
            setIsLoading(false);
        }
    };

    const handleApplyReference = async () => {
        const manualCorrections = (Object.entries(treatedRows) as [string, TreatedRow][])
            .filter(([_, data]) => data.status === 'manual')
            .map(([idx, data]) => ({
                originalRow: rawRows[parseInt(idx)],
                corrected: { date: data.date, name: data.name, amount: data.amount }
            }));

        if (manualCorrections.length === 0) {
            showToast("Edite uma linha para treinar a IA.", "error");
            return;
        }

        setIsLearning(true);
        try {
            const cleanRowsForLearning = rawRows.map(r => r.map(c => c.trim()));
            const aiResults = await learnAndTransformFile(cleanRowsForLearning, manualCorrections);

            const newTreated = { ...treatedRows };
            aiResults.forEach((res: any) => {
                const idx = res.originalIndex;
                if (newTreated[idx] && newTreated[idx].status !== 'manual' && newTreated[idx].status !== 'deleted') {
                    let status: TreatedRow['status'] = 'original';
                    if (res.name.includes('[suspeito]')) status = 'suspect';

                    newTreated[idx] = {
                        date: res.date,
                        name: res.name.replace('[suspeito] ', ''),
                        amount: res.amount,
                        status: status
                    };
                }
            });
            setTreatedRows(newTreated);
            showToast("Cérebro refinado com sucesso!", "success");
        } catch (error) {
            showToast("Falha no treinamento da IA.", "error");
        } finally {
            setIsLearning(false);
        }
    };

    const handleUpdateTreated = (idx: number, field: keyof TreatedRow, value: string) => {
        setTreatedRows(prev => ({
            ...prev,
            [idx]: { ...prev[idx], [field]: value, status: 'manual' }
        }));
        if (referenceRowIdx !== idx) setReferenceRowIdx(idx);
    };

    const handleDeleteRow = (idx: number) => {
        setTreatedRows(prev => ({
            ...prev,
            [idx]: { ...prev[idx], status: 'deleted' }
        }));
    };

    const handleRestoreRow = (idx: number) => {
        setTreatedRows(prev => ({
            ...prev,
            [idx]: { ...prev[idx], status: 'manual' }
        }));
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'text' && source.current && target.current) {
            target.current.scrollTop = source.current.scrollTop;
        }
    };

    const stats = useMemo(() => {
        const rows = Object.values(treatedRows) as TreatedRow[];
        return {
            manual: rows.filter(r => r.status === 'manual').length,
            suspect: rows.filter(r => r.status === 'suspect').length,
            deleted: rows.filter(r => r.status === 'deleted').length
        };
    }, [treatedRows]);

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1750px] h-[94vh] flex flex-col overflow-hidden shadow-2xl border border-white/20">

                {/* Header Superior */}
                <div className="flex items-center justify-between px-8 py-5 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="p-3 rounded-2xl text-white bg-gradient-to-br from-indigo-600 to-violet-600 shadow-lg">
                            <BrainIcon className="w-6 h-6" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Laboratório de Arquivos Inteligente</h3>
                            <div className="flex items-center gap-2 mt-0.5">
                                <span className="text-[10px] font-bold text-brand-blue uppercase tracking-widest">
                                    {isInitialInfering ? 'Analizando Estrutura...' : `Inteligência: ${stats.manual} Exemplos | ${stats.suspect} Suspeitos`}
                                </span>
                                <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{initialFile?.fileName}</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                         <button 
                            onClick={handleFinalize} 
                            className="flex items-center gap-2 px-6 py-2.5 bg-gradient-to-r from-emerald-600 to-teal-500 text-white rounded-full font-black text-[10px] uppercase tracking-widest shadow-lg shadow-emerald-500/20 hover:-translate-y-0.5 transition-all"
                        >
                            <FloppyDiskIcon className="w-4 h-4" />
                            Confirmar e Salvar Modelo
                        </button>
                        <button onClick={onClose} className="p-2.5 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-slate-50 dark:bg-slate-950">

                    {/* ESQUERDA: ORIGINAL REAL */}
                    <div className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-200 dark:bg-slate-950">

                        {/* Seletor de Modo na Esquerda */}
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-400" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Arquivo Original Real</span>
                            </div>

                            <div className="flex bg-slate-100 dark:bg-slate-900 p-1 rounded-full border border-slate-200 dark:border-slate-700 shadow-inner">
                                <button
                                    onClick={() => setViewMode('original')}
                                    className={`flex items-center gap-1.5 px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-sm border border-slate-100 dark:border-slate-600' : 'text-slate-400 hover:text-slate-600'}`}
                                >
                                    Visualização Real
                                </button>
                                <button
                                    onClick={() => setViewMode('text')}
                                    className={`flex items-center gap-1.5 px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'text' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-sm border border-slate-100 dark:border-slate-600' : 'text-slate-400 hover:text-slate-600'}`}
                                >
                                    Modo Células
                                </button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-hidden relative">
                            {viewMode === 'original' ? (
                                <div className="h-full w-full bg-slate-200 dark:bg-slate-900 overflow-auto">
                                    {isPdf && currentFileUrl ? (
                                        <div className="h-full w-full bg-slate-800 animate-fade-in">
                                            <embed 
                                                src={`${currentFileUrl}#toolbar=0&navpanes=0&scrollbar=1`} 
                                                className="w-full h-full border-none shadow-2xl"
                                                type="application/pdf"
                                            />
                                        </div>
                                    ) : isExcel && excelHtml ? (
                                        <div className="h-full w-full p-6 animate-fade-in">
                                            <div 
                                                className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-lg border border-slate-300 dark:border-slate-700 overflow-auto excel-preview"
                                                dangerouslySetInnerHTML={{ __html: excelHtml }}
                                            />
                                            <style>{`
                                                .excel-preview table { border-collapse: collapse; width: 100%; font-family: sans-serif; font-size: 12px; color: #1e293b; }
                                                .excel-preview td { border: 1px solid #e2e8f0; padding: 4px 8px; white-space: nowrap; }
                                                .dark .excel-preview td { border-color: #334155; color: #cbd5e1; }
                                                .excel-preview tr:nth-child(even) { background-color: #f8fafc; }
                                                .dark .excel-preview tr:nth-child(even) { background-color: #1e293b; }
                                            `}</style>
                                        </div>
                                    ) : (
                                        <div className="h-full overflow-auto p-8 custom-scrollbar">
                                            <div className="max-w-4xl mx-auto">
                                                <pre className="text-[12px] font-mono text-slate-700 dark:text-slate-300 whitespace-pre-wrap bg-white dark:bg-slate-800 p-10 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-700 min-h-full leading-relaxed selection:bg-blue-500 selection:text-white">
                                                    {initialFile?.content || 'Carregando conteúdo original...'}
                                                </pre>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="h-full overflow-auto custom-scrollbar bg-white dark:bg-slate-900">
                                    <table className="w-full text-[11px] border-collapse">
                                        <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b border-slate-200 shadow-sm">
                                            <tr>
                                                <th className="w-12 px-3 py-2 text-center text-[9px] text-slate-400 border-r border-slate-200 uppercase">#</th>
                                                {rawRows[0]?.map((_, i) => (
                                                    <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase tracking-tighter border-r border-slate-200 min-w-[150px]">Coluna {i+1}</th>
                                                ))}
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {rawRows.map((row, idx) => (
                                                <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group transition-all cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-800/50'}`}>
                                                    <td className={`text-center font-mono text-[9px] font-bold py-2 border-r border-slate-200 ${referenceRowIdx === idx ? 'bg-indigo-600 text-white shadow-lg' : treatedRows[idx]?.status === 'manual' ? 'bg-amber-50 text-white' : treatedRows[idx]?.status === 'deleted' ? 'bg-slate-300 text-slate-500' : 'text-slate-400 bg-slate-50 dark:bg-slate-800/50'}`}>{idx + 1}</td>
                                                    {row.map((cell, cIdx) => (
                                                        <td key={cIdx} className={`px-3 py-2 border-r border-slate-100 dark:border-slate-800 last:border-0 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] ${treatedRows[idx]?.status === 'deleted' ? 'opacity-30 line-through' : referenceRowIdx === idx ? 'text-indigo-700 dark:text-indigo-300 font-black' : 'text-slate-500 dark:text-slate-400'}`}>
                                                            <span className="whitespace-pre">{cell === "" ? <span className="opacity-10">---</span> : cell}</span>
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* DIREITA: RESULTADO DA IA */}
                    <div className="flex-1 flex flex-col bg-white dark:bg-slate-900/80 backdrop-blur-sm">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                            <div className="flex items-center gap-2">
                                <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Resultado Tratado pela IA</span>
                            </div>

                            <div className="flex items-center gap-2">
                                {stats.manual > 0 && (
                                    <button onClick={handleApplyReference} disabled={isLearning} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-500/30 hover:bg-indigo-500 hover:-translate-y-0.5 transition-all animate-scale-in">
                                        {isLearning ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />}
                                        Treinar Motor ({stats.manual})
                                    </button>
                                )}
                            </div>
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b border-slate-200">
                                    <tr>
                                        <th className="px-4 py-3 text-left w-28 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição Limpa</th>
                                        <th className="px-4 py-3 text-right w-28 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-4 py-3 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-700/50">
                                    {rawRows.map((_, idx) => {
                                        const row = treatedRows[idx];
                                        if (!row) return null;

                                        const isDeleted = row.status === 'deleted';
                                        const isSuspect = row.status === 'suspect';
                                        const isManual = row.status === 'manual';
                                        const amountVal = parseFloat(row.amount.replace(',', '.'));

                                        return (
                                            <tr key={idx} className={`transition-colors group h-[42px] ${referenceRowIdx === idx ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : isDeleted ? 'bg-slate-50/50 grayscale' : isSuspect ? 'bg-amber-50/30' : ''}`}>
                                                <td className="px-4 py-0">
                                                    <input type="text" value={row.date} onChange={(e) => handleUpdateTreated(idx, 'date', e.target.value)} disabled={isDeleted} className={`w-full bg-transparent border-none outline-none font-mono text-[11px] ${isDeleted ? 'opacity-30' : 'text-slate-600 dark:text-slate-300'}`} placeholder="---" />
                                                </td>
                                                <td className="px-4 py-0 relative">
                                                    <div className="flex items-center gap-2 h-full">
                                                        {isSuspect && <ExclamationTriangleIcon className="w-3.5 h-3.5 text-amber-500 shrink-0" title="Possível Saldo ou Total" />}
                                                        <input type="text" value={row.name} onChange={(e) => handleUpdateTreated(idx, 'name', e.target.value)} disabled={isDeleted} className={`w-full bg-transparent border-none outline-none text-[11px] font-bold ${isDeleted ? 'opacity-30 line-through' : isSuspect ? 'text-amber-700' : isManual ? 'text-indigo-600' : 'text-slate-900 dark:text-white'}`} placeholder="vazio" />
                                                    </div>
                                                </td>
                                                <td className="px-4 py-0">
                                                    <input type="text" value={row.amount} onChange={(e) => handleUpdateTreated(idx, 'amount', e.target.value)} disabled={isDeleted} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[11px] font-black ${isDeleted ? 'opacity-30' : amountVal < 0 ? 'text-red-600' : 'text-emerald-600'}`} placeholder="0,00" />
                                                </td>
                                                <td className="px-2 py-0 text-center">
                                                    {isDeleted ? (
                                                        <button onClick={() => handleRestoreRow(idx)} className="p-1 text-emerald-500 hover:scale-110 transition-transform" title="Restaurar">
                                                            <ArrowPathIcon className="w-4 h-4" />
                                                        </button>
                                                    ) : (
                                                        <button onClick={() => handleDeleteRow(idx)} className={`p-1 transition-all ${isSuspect ? 'text-amber-500 opacity-100' : 'text-slate-300 opacity-0 group-hover:opacity-100 hover:text-red-500'}`} title={isSuspect ? "Remover Saldo/Total" : "Remover Linha"}>
                                                            <TrashIcon className="w-4 h-4" />
                                                        </button>
                                                    )}
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                <div className="px-8 py-3 bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex items-center gap-6 shrink-0">
                    <div className="flex items-center gap-2 text-[9px] text-amber-600 font-bold uppercase"><div className="w-2.5 h-2.5 rounded bg-amber-500 shadow-sm"></div><span>Exemplo Treino</span></div>
                    <div className="flex items-center gap-2 text-[9px] text-red-600 font-bold uppercase"><div className="w-2.5 h-2.5 rounded bg-red-100 border border-red-200"></div><span>Valor Negativo</span></div>
                    <div className="flex items-center gap-2 text-[9px] text-slate-500 font-bold uppercase"><div className="w-2.5 h-2.5 rounded bg-amber-100 border border-amber-300"></div><span>Saldo (Suspeito)</span></div>

                    <div className="ml-auto p-2 bg-blue-50 dark:bg-blue-900/30 rounded-xl border border-blue-100 dark:border-blue-800 max-w-lg">
                        <p className="text-[9px] text-blue-700 dark:text-blue-300 leading-tight">
                            <strong>Dica Profissional:</strong> Edite algumas linhas na direita para ensinar à IA como o seu arquivo deve ser lido. Depois, clique em "Treinar Motor" para processar o resto.
                        </p>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    PhotoIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction, MatchResult } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted';
}

type ViewMode = 'original' | 'text';

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<Record<number, TreatedRow>>({});
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isLearning, setIsLearning] = useState(false);
    const [isInitialInfering, setIsInitialInfering] = useState(false);
    const [viewMode, setViewMode] = useState<ViewMode>('original');
    const [currentFileUrl, setCurrentFileUrl] = useState<string | null>(null);
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    useEffect(() => {
        if (!initialFile) return;

        // 1. Processamento para o motor de IA e modo Células
        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = ';';
            const firstDataLine = lines.find(l => l.includes(';') || l.includes(',') || l.includes('\t')) || lines[0];
            if (firstDataLine.includes('\t')) delimiter = '\t';
            else if (!firstDataLine.includes(';') && firstDataLine.includes(',')) delimiter = ',';

            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initialTreated: Record<number, TreatedRow> = {};
            parsed.forEach((_, idx) => {
                initialTreated[idx] = { date: '', name: '[processando...]', amount: '0,00', status: 'unrecognized' };
            });
            setTreatedRows(initialTreated);
            triggerInitialInference(parsed);
        }

        // 2. Carregamento do Visualizador Real (PDF / Excel / Texto)
        const fileObj = initialFile.rawFile;
        if (fileObj) {
            // Garantir que temos um Blob válido
            const blob = fileObj instanceof Blob ? fileObj : new Blob([fileObj], { type: isPdf ? 'application/pdf' : (fileObj.type || 'text/plain') });

            if (isPdf) {
                const url = URL.createObjectURL(blob);
                setCurrentFileUrl(url);
                return () => URL.revokeObjectURL(url);
            } else if (isExcel) {
                const reader = new FileReader();
                reader.onload = (e) => {
                    try {
                        const data = new Uint8Array(e.target?.result as ArrayBuffer);
                        const workbook = XLSX.read(data, { type: 'array' });
                        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                        const html = XLSX.utils.sheet_to_html(firstSheet, { editable: false, header: '', footer: '' });
                        setExcelHtml(html);
                    } catch (err) {
                        console.error("Erro Excel:", err);
                    }
                };
                reader.readAsArrayBuffer(blob);
            }
        }
    }, [initialFile, isPdf, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        setIsInitialInfering(true);
        try {
            const cleanSample = rows
                .map((r, i) => ({ row: r.map(c => c.trim()), index: i }))
                .filter(item => item.row.some(c => c.length > 0))
                .slice(0, 60);

            const initialGuess = await performInitialInference(cleanSample.map(s => s.row));

            setTreatedRows(prev => {
                const newTreated = { ...prev };
                initialGuess.forEach((res: any, idx: number) => {
                    const originalIdx = cleanSample[idx]?.index;
                    if (originalIdx !== undefined) {
                        let status: TreatedRow['status'] = 'inferred';
                        if (res.name.includes('[suspeito]')) status = 'suspect';
                        newTreated[originalIdx] = {
                            date: res.date,
                            name: res.name.replace('[suspeito] ', ''),
                            amount: res.amount,
                            status: status
                        };
                    }
                });
                return newTreated;
            });
        } catch (e) {
            console.error("Erro inferência:", e);
        } finally {
            setIsInitialInfering(false);
        }
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                // Cálculo de mapeamento simplificado para salvar
                const manual = Object.entries(treatedRows).find(([_, d]) => d.status === 'manual');
                const mapping = manual ? {
                    dateColumnIndex: rawRows[parseInt(manual[0])].findIndex(c => c.includes(manual[1].date.split('-')[2])),
                    descriptionColumnIndex: 1, // Fallback
                    amountColumnIndex: 2  // Fallback
                } : { dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2 };

                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id,
                    version: 1,
                    lineage_id: `lin-${Date.now()}`,
                    is_active: true,
                    fingerprint: fingerprint,
                    mapping: {
                        dateColumnIndex: mapping.dateColumnIndex !== -1 ? mapping.dateColumnIndex : 0,
                        descriptionColumnIndex: 1,
                        amountColumnIndex: 2,
                        skipRowsStart: 1,
                        skipRowsEnd: 0,
                        decimalSeparator: ',',
                        thousandsSeparator: '.'
                    },
                    parsingRules: {
                        ignoredKeywords: customIgnoreKeywords,
                        rowFilters: (Object.values(treatedRows) as TreatedRow[])
                            .filter(r => r.status === 'deleted').map(r => r.name)
                    }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Layout salvo!", "success");
            }
            onClose();
        } catch (e) {
            showToast("Erro ao salvar.", "error");
        } finally {
            setIsLoading(false);
        }
    };

    const handleApplyReference = async () => {
        const manual = (Object.entries(treatedRows) as [string, TreatedRow][])
            .filter(([_, d]) => d.status === 'manual')
            .map(([idx, d]) => ({
                originalRow: rawRows[parseInt(idx)],
                corrected: { date: d.date, name: d.name, amount: d.amount }
            }));

        if (manual.length === 0) {
            showToast("Edite uma linha primeiro.", "error");
            return;
        }

        setIsLearning(true);
        try {
            const aiResults = await learnAndTransformFile(rawRows.map(r => r.map(c => c.trim())), manual);
            const newTreated = { ...treatedRows };
            aiResults.forEach((res: any) => {
                const idx = res.originalIndex;
                if (newTreated[idx] && newTreated[idx].status !== 'manual' && newTreated[idx].status !== 'deleted') {
                    newTreated[idx] = {
                        date: res.date,
                        name: res.name.replace('[suspeito] ', ''),
                        amount: res.amount,
                        status: res.name.includes('[suspeito]') ? 'suspect' : 'original'
                    };
                }
            });
            setTreatedRows(newTreated);
            showToast("Cérebro atualizado!", "success");
        } catch (error) {
            showToast("Erro no treino.", "error");
        } finally {
            setIsLearning(false);
        }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'text' && source.current && target.current) {
            target.current.scrollTop = source.current.scrollTop;
        }
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1750px] h-[94vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                {/* Header Superior */}
                <div className="flex items-center justify-between px-8 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white/50 dark:bg-slate-900/50 backdrop-blur-md">
                    <div className="flex items-center gap-4">
                        <div className="p-3 rounded-2xl text-white bg-gradient-to-br from-indigo-600 to-violet-600 shadow-lg">
                            <BrainIcon className="w-6 h-6" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Laboratório de Arquivos</h3>
                            <div className="flex items-center gap-2 mt-0.5">
                                <span className="text-[10px] font-bold text-brand-blue uppercase tracking-widest">Original vs Interpretado</span>
                                <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{initialFile?.fileName}</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                         <button onClick={handleFinalize} className="flex items-center gap-2 px-6 py-2.5 bg-emerald-600 text-white rounded-full font-black text-[10px] uppercase tracking-widest shadow-lg hover:bg-emerald-500 transition-all">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar Modelo
                        </button>
                        <button onClick={onClose} className="p-2.5 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-slate-50 dark:bg-slate-950">

                    {/* ESQUERDA: ORIGINAL REAL */}
                    <div className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14]">

                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-400" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Visualização Original</span>
                            </div>

                            <div className="flex bg-slate-100 dark:bg-slate-950 p-1 rounded-full border border-slate-200 dark:border-slate-800">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-800 text-brand-blue shadow-sm border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>Real</button>
                                <button onClick={() => setViewMode('text')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'text' ? 'bg-white dark:bg-slate-800 text-brand-blue shadow-sm border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-hidden relative">
                            {viewMode === 'original' ? (
                                <div className="h-full w-full bg-slate-200 dark:bg-[#020610] overflow-auto">
                                    {isPdf && currentFileUrl ? (
                                        <div className="h-full w-full animate-fade-in">
                                            <iframe 
                                                src={`${currentFileUrl}#toolbar=0&navpanes=0&scrollbar=1`} 
                                                className="w-full h-full border-none"
                                                title="PDF Preview"
                                            />
                                        </div>
                                    ) : isExcel && excelHtml ? (
                                        <div className="h-full w-full p-8 animate-fade-in">
                                            <div 
                                                className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-300 dark:border-slate-700 overflow-auto excel-preview select-all"
                                                dangerouslySetInnerHTML={{ __html: excelHtml }}
                                            />
                                            <style>{`
                                                .excel-preview table { border-collapse: collapse; width: 100%; font-family: 'Inter', sans-serif; font-size: 11px; color: #1e293b; }
                                                .excel-preview td { border: 1px solid #e2e8f0; padding: 6px 10px; white-space: nowrap; }
                                                .dark .excel-preview td { border-color: #334155; color: #cbd5e1; }
                                                .excel-preview tr:nth-child(even) { background-color: #f8fafc; }
                                                .dark .excel-preview tr:nth-child(even) { background-color: #1e293b; }
                                            `}</style>
                                        </div>
                                    ) : (
                                        <div className="h-full overflow-auto p-10 custom-scrollbar">
                                            <div className="max-w-5xl mx-auto">
                                                <pre className="text-[12px] font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-12 rounded-[2rem] shadow-2xl border border-slate-200 dark:border-slate-700 min-h-full leading-relaxed selection:bg-blue-500 selection:text-white tab-size-4">
                                                    {initialFile?.content || 'Carregando...'}
                                                </pre>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="h-full overflow-auto custom-scrollbar bg-white dark:bg-slate-900">
                                    <table className="w-full text-[11px] border-collapse">
                                        <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b border-slate-200 shadow-sm">
                                            <tr>
                                                <th className="w-12 px-3 py-2 text-center text-[9px] text-slate-400 border-r border-slate-200">#</th>
                                                {rawRows[0]?.map((_, i) => (
                                                    <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase tracking-tighter border-r border-slate-200 min-w-[150px]">Col {i+1}</th>
                                                ))}
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {rawRows.map((row, idx) => (
                                                <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group transition-all cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-800/50'}`}>
                                                    <td className={`text-center font-mono text-[9px] font-bold py-2 border-r border-slate-200 ${referenceRowIdx === idx ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 bg-slate-50 dark:bg-slate-800/50'}`}>{idx + 1}</td>
                                                    {row.map((cell, cIdx) => (
                                                        <td key={cIdx} className={`px-3 py-2 border-r border-slate-100 dark:border-slate-800 last:border-0 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] ${treatedRows[idx]?.status === 'deleted' ? 'opacity-30 line-through' : 'text-slate-500 dark:text-slate-400'}`}>
                                                            {cell || <span className="opacity-10">---</span>}
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* DIREITA: IA */}
                    <div className="flex-1 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)]">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                            <div className="flex items-center gap-2">
                                <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Motor de Inteligência</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <button onClick={handleApplyReference} disabled={isLearning} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg hover:bg-indigo-500 transition-all">
                                    {isLearning ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />}
                                    Treinar Motor
                                </button>
                            </div>
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b border-slate-200">
                                    <tr>
                                        <th className="px-4 py-3 text-left w-28 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                                        <th className="px-4 py-3 text-right w-28 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-4 py-3 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-700/50">
                                    {rawRows.map((_, idx) => {
                                        const row = treatedRows[idx];
                                        if (!row) return null;
                                        return (
                                            <tr key={idx} className={`transition-colors h-[42px] ${referenceRowIdx === idx ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : row.status === 'deleted' ? 'bg-slate-50/50 grayscale' : ''}`}>
                                                <td className="px-4 py-0">
                                                    <input type="text" value={row.date} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], date: e.target.value, status: 'manual'}}))} className="w-full bg-transparent border-none outline-none font-mono text-[11px] text-slate-600 dark:text-slate-300" placeholder="---" />
                                                </td>
                                                <td className="px-4 py-0 flex items-center gap-2 h-full">
                                                    {row.status === 'suspect' && <ExclamationTriangleIcon className="w-3.5 h-3.5 text-amber-500 shrink-0" />}
                                                    <input type="text" value={row.name} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], name: e.target.value, status: 'manual'}}))} className={`w-full bg-transparent border-none outline-none text-[11px] font-bold ${row.status === 'manual' ? 'text-indigo-600' : 'text-slate-900 dark:text-white'}`} placeholder="vazio" />
                                                </td>
                                                <td className="px-4 py-0">
                                                    <input type="text" value={row.amount} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], amount: e.target.value, status: 'manual'}}))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[11px] font-black ${parseFloat(row.amount) < 0 ? 'text-red-600' : 'text-emerald-600'}`} placeholder="0,00" />
                                                </td>
                                                <td className="px-2 py-0 text-center">
                                                    <button onClick={() => setTreatedRows(p => ({...p, [idx]: {...p[idx], status: p[idx].status === 'deleted' ? 'manual' : 'deleted'}}))} className="p-1 text-slate-300 hover:text-red-500 transition-colors">
                                                        {row.status === 'deleted' ? <ArrowPathIcon className="w-4 h-4 text-emerald-500" /> : <TrashIcon className="w-4 h-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                <div className="px-8 py-3 bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex items-center gap-6 shrink-0">
                    <p className="text-[9px] text-blue-700 dark:text-blue-300 leading-tight">
                        <strong>Dica:</strong> Edite uma linha na direita para que a IA aprenda o padrão do seu extrato e clique em "Treinar Motor".
                    </p>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    PhotoIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction, MatchResult } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted';
}

type ViewMode = 'original' | 'text';

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<Record<number, TreatedRow>>({});
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isLearning, setIsLearning] = useState(false);
    const [isInitialInfering, setIsInitialInfering] = useState(false);
    const [viewMode, setViewMode] = useState<ViewMode>('original');
    const [currentFileUrl, setCurrentFileUrl] = useState<string | null>(null);
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    useEffect(() => {
        if (!initialFile) return;

        // 1. Processamento para o motor de IA e modo Células
        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = ';';
            const firstDataLine = lines.find(l => l.includes(';') || l.includes(',') || l.includes('\t')) || lines[0];
            if (firstDataLine.includes('\t')) delimiter = '\t';
            else if (!firstDataLine.includes(';') && firstDataLine.includes(',')) delimiter = ',';

            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initialTreated: Record<number, TreatedRow> = {};
            parsed.forEach((_, idx) => {
                initialTreated[idx] = { date: '', name: '[processando...]', amount: '0,00', status: 'unrecognized' };
            });
            setTreatedRows(initialTreated);
            triggerInitialInference(parsed);
        }

        // 2. Carregamento do Visualizador Real (PDF / Excel / Texto)
        const fileObj = initialFile.rawFile;
        if (fileObj) {
            // Garantir que temos um Blob válido
            const blob = fileObj instanceof Blob ? fileObj : new Blob([fileObj], { type: isPdf ? 'application/pdf' : (fileObj.type || 'text/plain') });

            if (isPdf) {
                const url = URL.createObjectURL(blob);
                setCurrentFileUrl(url);
                return () => URL.revokeObjectURL(url);
            } else if (isExcel) {
                const reader = new FileReader();
                reader.onload = (e) => {
                    try {
                        const data = new Uint8Array(e.target?.result as ArrayBuffer);
                        const workbook = XLSX.read(data, { type: 'array' });
                        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                        const html = XLSX.utils.sheet_to_html(firstSheet, { editable: false, header: '', footer: '' });
                        setExcelHtml(html);
                    } catch (err) {
                        console.error("Erro Excel:", err);
                    }
                };
                reader.readAsArrayBuffer(blob);
            }
        }
    }, [initialFile, isPdf, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        setIsInitialInfering(true);
        try {
            const cleanSample = rows
                .map((r, i) => ({ row: r.map(c => c.trim()), index: i }))
                .filter(item => item.row.some(c => c.length > 0))
                .slice(0, 60);

            const initialGuess = await performInitialInference(cleanSample.map(s => s.row));

            setTreatedRows(prev => {
                const newTreated = { ...prev };
                initialGuess.forEach((res: any, idx: number) => {
                    const originalIdx = cleanSample[idx]?.index;
                    if (originalIdx !== undefined) {
                        let status: TreatedRow['status'] = 'inferred';
                        if (res.name.includes('[suspeito]')) status = 'suspect';
                        newTreated[originalIdx] = {
                            date: res.date,
                            name: res.name.replace('[suspeito] ', ''),
                            amount: res.amount,
                            status: status
                        };
                    }
                });
                return newTreated;
            });
        } catch (e) {
            console.error("Erro inferência:", e);
        } finally {
            setIsInitialInfering(false);
        }
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                // Cálculo de mapeamento simplificado para salvar
                const manual = Object.entries(treatedRows).find(([_, d]) => (d as TreatedRow).status === 'manual');
                const mapping = manual ? {
                    dateColumnIndex: rawRows[parseInt(manual[0])].findIndex(c => c.includes((manual[1] as TreatedRow).date.split('-')[2])),
                    descriptionColumnIndex: 1, // Fallback
                    amountColumnIndex: 2  // Fallback
                } : { dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2 };

                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id,
                    version: 1,
                    lineage_id: `lin-${Date.now()}`,
                    is_active: true,
                    fingerprint: fingerprint,
                    mapping: {
                        dateColumnIndex: mapping.dateColumnIndex !== -1 ? mapping.dateColumnIndex : 0,
                        descriptionColumnIndex: 1,
                        amountColumnIndex: 2,
                        skipRowsStart: 1,
                        skipRowsEnd: 0,
                        decimalSeparator: ',',
                        thousandsSeparator: '.'
                    },
                    parsingRules: {
                        ignoredKeywords: customIgnoreKeywords,
                        rowFilters: (Object.values(treatedRows) as TreatedRow[])
                            .filter(r => r.status === 'deleted').map(r => r.name)
                    }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Layout salvo!", "success");
            }
            onClose();
        } catch (e) {
            showToast("Erro ao salvar.", "error");
        } finally {
            setIsLoading(false);
        }
    };

    const handleApplyReference = async () => {
        // Fix: Explicitly cast entries to handle 'unknown' type errors during filter/map
        const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
        const manual = entries
            // Fix: Property 'status' does not exist on type 'unknown' (Ensuring d is TreatedRow)
            .filter(([, d]) => d.status === 'manual')
            // Fix: Property 'date' does not exist on type 'unknown' (Ensuring d is TreatedRow)
            .map(([idx, d]) => ({
                originalRow: rawRows[parseInt(idx)],
                corrected: { date: d.date, name: d.name, amount: d.amount }
            }));

        if (manual.length === 0) {
            showToast("Edite uma linha primeiro.", "error");
            return;
        }

        setIsLearning(true);
        try {
            const aiResults = await learnAndTransformFile(rawRows.map(r => r.map(c => c.trim())), manual);
            const newTreated = { ...treatedRows };
            aiResults.forEach((res: any) => {
                const idx = res.originalIndex;
                if (newTreated[idx] && newTreated[idx].status !== 'manual' && newTreated[idx].status !== 'deleted') {
                    newTreated[idx] = {
                        date: res.date,
                        name: res.name.replace('[suspeito] ', ''),
                        amount: res.amount,
                        status: res.name.includes('[suspeito]') ? 'suspect' : 'original'
                    };
                }
            });
            setTreatedRows(newTreated);
            showToast("Cérebro atualizado!", "success");
        } catch (error) {
            showToast("Erro no treino.", "error");
        } finally {
            setIsLearning(false);
        }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'text' && source.current && target.current) {
            target.current.scrollTop = source.current.scrollTop;
        }
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1750px] h-[94vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                {/* Header Superior */}
                <div className="flex items-center justify-between px-8 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white/50 dark:bg-slate-900/50 backdrop-blur-md">
                    <div className="flex items-center gap-4">
                        <div className="p-3 rounded-2xl text-white bg-gradient-to-br from-indigo-600 to-violet-600 shadow-lg">
                            <BrainIcon className="w-6 h-6" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Laboratório de Arquivos</h3>
                            <div className="flex items-center gap-2 mt-0.5">
                                <span className="text-[10px] font-bold text-brand-blue uppercase tracking-widest">Original vs Interpretado</span>
                                <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{initialFile?.fileName}</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                         <button onClick={handleFinalize} className="flex items-center gap-2 px-6 py-2.5 bg-emerald-600 text-white rounded-full font-black text-[10px] uppercase tracking-widest shadow-lg hover:bg-emerald-500 transition-all">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar Modelo
                        </button>
                        <button onClick={onClose} className="p-2.5 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-slate-50 dark:bg-slate-950">

                    {/* ESQUERDA: ORIGINAL REAL */}
                    <div className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14]">

                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-400" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Visualização Original</span>
                            </div>

                            <div className="flex bg-slate-100 dark:bg-slate-950 p-1 rounded-full border border-slate-200 dark:border-slate-800">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-800 text-brand-blue shadow-sm border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>Real</button>
                                <button onClick={() => setViewMode('text')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'text' ? 'bg-white dark:bg-slate-800 text-brand-blue shadow-sm border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-hidden relative">
                            {viewMode === 'original' ? (
                                <div className="h-full w-full bg-slate-200 dark:bg-[#020610] overflow-auto">
                                    {isPdf && currentFileUrl ? (
                                        <div className="h-full w-full animate-fade-in">
                                            <iframe 
                                                src={`${currentFileUrl}#toolbar=0&navpanes=0&scrollbar=1`} 
                                                className="w-full h-full border-none"
                                                title="PDF Preview"
                                            />
                                        </div>
                                    ) : isExcel && excelHtml ? (
                                        <div className="h-full w-full p-8 animate-fade-in">
                                            <div 
                                                className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-300 dark:border-slate-700 overflow-auto excel-preview select-all"
                                                dangerouslySetInnerHTML={{ __html: excelHtml }}
                                            />
                                            <style>{`
                                                .excel-preview table { border-collapse: collapse; width: 100%; font-family: 'Inter', sans-serif; font-size: 11px; color: #1e293b; }
                                                .excel-preview td { border: 1px solid #e2e8f0; padding: 6px 10px; white-space: nowrap; }
                                                .dark .excel-preview td { border-color: #334155; color: #cbd5e1; }
                                                .excel-preview tr:nth-child(even) { background-color: #f8fafc; }
                                                .dark .excel-preview tr:nth-child(even) { background-color: #1e293b; }
                                            `}</style>
                                        </div>
                                    ) : (
                                        <div className="h-full overflow-auto p-10 custom-scrollbar">
                                            <div className="max-w-5xl mx-auto">
                                                <pre className="text-[12px] font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-12 rounded-[2rem] shadow-2xl border border-slate-200 dark:border-slate-700 min-h-full leading-relaxed selection:bg-blue-500 selection:text-white tab-size-4">
                                                    {initialFile?.content || 'Carregando...'}
                                                </pre>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="h-full overflow-auto custom-scrollbar bg-white dark:bg-slate-900">
                                    <table className="w-full text-[11px] border-collapse">
                                        <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b border-slate-200 shadow-sm">
                                            <tr>
                                                <th className="w-12 px-3 py-2 text-center text-[9px] text-slate-400 border-r border-slate-200">#</th>
                                                {rawRows[0]?.map((_, i) => (
                                                    <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase tracking-tighter border-r border-slate-200 min-w-[150px]">Col {i+1}</th>
                                                ))}
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {rawRows.map((row, idx) => (
                                                <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group transition-all cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-800/50'}`}>
                                                    <td className={`text-center font-mono text-[9px] font-bold py-2 border-r border-slate-200 ${referenceRowIdx === idx ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 bg-slate-50 dark:bg-slate-800/50'}`}>{idx + 1}</td>
                                                    {row.map((cell, cIdx) => (
                                                        <td key={cIdx} className={`px-3 py-2 border-r border-slate-100 dark:border-slate-800 last:border-0 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] ${treatedRows[idx]?.status === 'deleted' ? 'opacity-30 line-through' : 'text-slate-500 dark:text-slate-400'}`}>
                                                            {cell || <span className="opacity-10">---</span>}
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* DIREITA: IA */}
                    <div className="flex-1 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)]">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                            <div className="flex items-center gap-2">
                                <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Motor de Inteligência</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <button onClick={handleApplyReference} disabled={isLearning} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg hover:bg-indigo-500 transition-all">
                                    {isLearning ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />}
                                    Treinar Motor
                                </button>
                            </div>
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b border-slate-200">
                                    <tr>
                                        <th className="px-4 py-3 text-left w-28 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                                        <th className="px-4 py-3 text-right w-28 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-4 py-3 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-700/50">
                                    {rawRows.map((_, idx) => {
                                        const row = treatedRows[idx];
                                        if (!row) return null;
                                        return (
                                            <tr key={idx} className={`transition-colors h-[42px] ${referenceRowIdx === idx ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : row.status === 'deleted' ? 'bg-slate-50/50 grayscale' : ''}`}>
                                                <td className="px-4 py-0">
                                                    <input type="text" value={row.date} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], date: e.target.value, status: 'manual'}}))} className="w-full bg-transparent border-none outline-none font-mono text-[11px] text-slate-600 dark:text-slate-300" placeholder="---" />
                                                </td>
                                                <td className="px-4 py-0 flex items-center gap-2 h-full">
                                                    {row.status === 'suspect' && <ExclamationTriangleIcon className="w-3.5 h-3.5 text-amber-500 shrink-0" />}
                                                    <input type="text" value={row.name} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], name: e.target.value, status: 'manual'}}))} className={`w-full bg-transparent border-none outline-none text-[11px] font-bold ${row.status === 'manual' ? 'text-indigo-600' : 'text-slate-900 dark:text-white'}`} placeholder="vazio" />
                                                </td>
                                                <td className="px-4 py-0">
                                                    <input type="text" value={row.amount} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], amount: e.target.value, status: 'manual'}}))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[11px] font-black ${parseFloat(row.amount) < 0 ? 'text-red-600' : 'text-emerald-600'}`} placeholder="0,00" />
                                                </td>
                                                <td className="px-2 py-0 text-center">
                                                    <button onClick={() => setTreatedRows(p => ({...p, [idx]: {...p[idx], status: p[idx].status === 'deleted' ? 'manual' : 'deleted'}}))} className="p-1 text-slate-300 hover:text-red-500 transition-colors">
                                                        {row.status === 'deleted' ? <ArrowPathIcon className="w-4 h-4 text-emerald-500" /> : <TrashIcon className="w-4 h-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                <div className="px-8 py-3 bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex items-center gap-6 shrink-0">
                    <p className="text-[9px] text-blue-700 dark:text-blue-300 leading-tight">
                        <strong>Dica:</strong> Edite uma linha na direita para que a IA aprenda o padrão do seu extrato e clique em "Treinar Motor".
                    </p>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    DocumentArrowDownIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction, MatchResult } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted';
}

type ViewMode = 'original' | 'text';

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<Record<number, TreatedRow>>({});
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isLearning, setIsLearning] = useState(false);
    const [isInitialInfering, setIsInitialInfering] = useState(false);
    const [viewMode, setViewMode] = useState<ViewMode>('original');
    const [currentFileUrl, setCurrentFileUrl] = useState<string | null>(null);
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    useEffect(() => {
        if (!initialFile) return;

        // 1. Preparação dos dados para a IA e modo Células
        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = ';';
            const firstDataLine = lines.find(l => l.includes(';') || l.includes(',') || l.includes('\t')) || lines[0];
            if (firstDataLine.includes('\t')) delimiter = '\t';
            else if (!firstDataLine.includes(';') && firstDataLine.includes(',')) delimiter = ',';

            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initialTreated: Record<number, TreatedRow> = {};
            parsed.forEach((_, idx) => {
                initialTreated[idx] = { date: '', name: '[carregando...]', amount: '0,00', status: 'unrecognized' };
            });
            setTreatedRows(initialTreated);
            triggerInitialInference(parsed);
        }

        // 2. Carregamento do Visualizador do Arquivo REAL
        const raw = initialFile.rawFile;
        if (raw) {
            // Garantir que temos um Blob com o MIME-type correto
            const fileBlob = raw instanceof Blob ? raw : new Blob([raw], { type: isPdf ? 'application/pdf' : (raw.type || 'text/plain') });

            if (isPdf) {
                const url = URL.createObjectURL(fileBlob);
                setCurrentFileUrl(url);
                return () => URL.revokeObjectURL(url);
            } else if (isExcel) {
                const reader = new FileReader();
                reader.onload = (e) => {
                    try {
                        const data = new Uint8Array(e.target?.result as ArrayBuffer);
                        const workbook = XLSX.read(data, { type: 'array' });
                        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                        // Gerar HTML da planilha para visualização visual fiel
                        const html = XLSX.utils.sheet_to_html(firstSheet, { editable: false, header: '', footer: '' });
                        setExcelHtml(html);
                    } catch (err) {
                        console.error("Erro ao renderizar Excel:", err);
                    }
                };
                reader.readAsArrayBuffer(fileBlob);
            }
        }
    }, [initialFile, isPdf, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        setIsInitialInfering(true);
        try {
            const cleanSample = rows
                .map((r, i) => ({ row: r.map(c => c.trim()), index: i }))
                .filter(item => item.row.some(c => c.length > 0))
                .slice(0, 60);

            const initialGuess = await performInitialInference(cleanSample.map(s => s.row));

            setTreatedRows(prev => {
                const newTreated = { ...prev };
                initialGuess.forEach((res: any, idx: number) => {
                    const originalIdx = cleanSample[idx]?.index;
                    if (originalIdx !== undefined) {
                        newTreated[originalIdx] = {
                            date: res.date,
                            name: res.name.replace('[suspeito] ', ''),
                            amount: res.amount,
                            status: res.name.includes('[suspeito]') ? 'suspect' : 'inferred'
                        };
                    }
                });
                return newTreated;
            });
        } catch (e) {
            console.error("Erro inferência IA:", e);
        } finally {
            setIsInitialInfering(false);
        }
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
                const manual = entries.find(([, d]) => d.status === 'manual');

                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id,
                    version: 1,
                    lineage_id: `lin-${Date.now()}`,
                    is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: manual ? rawRows[parseInt(manual[0])].findIndex(c => c.includes(manual[1].date.split('-')[2])) : 0,
                        descriptionColumnIndex: 1,
                        amountColumnIndex: 2,
                        skipRowsStart: 1,
                        skipRowsEnd: 0,
                        decimalSeparator: ',',
                        thousandsSeparator: '.'
                    },
                    parsingRules: {
                        ignoredKeywords: customIgnoreKeywords,
                        rowFilters: (Object.values(treatedRows) as TreatedRow[])
                            .filter(r => r.status === 'deleted').map(r => r.name)
                    }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Layout de arquivo salvo!", "success");
            }
            onClose();
        } catch (e) {
            showToast("Erro ao salvar modelo.", "error");
        } finally {
            setIsLoading(false);
        }
    };

    const handleApplyReference = async () => {
        const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
        const manual = entries
            .filter(([, d]) => d.status === 'manual')
            .map(([idx, d]) => ({
                originalRow: rawRows[parseInt(idx)],
                corrected: { date: d.date, name: d.name, amount: d.amount }
            }));

        if (manual.length === 0) {
            showToast("Edite uma linha para ensinar a IA.", "error");
            return;
        }

        setIsLearning(true);
        try {
            const aiResults = await learnAndTransformFile(rawRows.map(r => r.map(c => c.trim())), manual);
            const newTreated = { ...treatedRows };
            aiResults.forEach((res: any) => {
                const idx = res.originalIndex;
                if (newTreated[idx] && newTreated[idx].status !== 'manual' && newTreated[idx].status !== 'deleted') {
                    newTreated[idx] = {
                        date: res.date,
                        name: res.name.replace('[suspeito] ', ''),
                        amount: res.amount,
                        status: res.name.includes('[suspeito]') ? 'suspect' : 'original'
                    };
                }
            });
            setTreatedRows(newTreated);
            showToast("IA treinada com sucesso!", "success");
