    const [isLearning, setIsLearning] = useState(false);
    const [isInitialInfering, setIsInitialInfering] = useState(false);
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    useEffect(() => {
        if (!initialFile) return;

        // Processamento para o modo Células
        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initialTreated: Record<number, TreatedRow> = {};
            parsed.forEach((_, idx) => {
                initialTreated[idx] = { date: '', name: '[carregando...]', amount: '0,00', status: 'unrecognized' };
            });
            setTreatedRows(initialTreated);
            triggerInitialInference(parsed);
        }

        // Processamento para o modo Excel Visual
        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const html = XLSX.utils.sheet_to_html(workbook.Sheets[workbook.SheetNames[0]]);
                setExcelHtml(html);
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        setIsInitialInfering(true);
        try {
            const sample = rows.map((r, i) => ({ row: r.map(c => c.trim()), index: i })).slice(0, 60);
            const initialGuess = await performInitialInference(sample.map(s => s.row));

            setTreatedRows(prev => {
                const newTreated = { ...prev };
                initialGuess.forEach((res: any, idx: number) => {
                    const originalIdx = sample[idx]?.index;
                    if (originalIdx !== undefined) {
                        newTreated[originalIdx] = {
                            date: res.date,
                            name: res.name.replace('[suspeito] ', ''),
                            amount: res.amount,
                            status: res.name.includes('[suspeito]') ? 'suspect' : 'inferred'
                        };
                    }
                });
                return newTreated;
            });
        } catch (e) {
            console.error("Erro IA:", e);
        } finally {
            setIsInitialInfering(false);
        }
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
                const manual = entries.find(([, d]) => d.status === 'manual');
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: manual ? rawRows[parseInt(manual[0])].findIndex(c => c.includes(manual[1].date.split('-')[2])) : 0,
                        descriptionColumnIndex: 1, amountColumnIndex: 2, skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { ignoredKeywords: customIgnoreKeywords, rowFilters: (Object.values(treatedRows) as TreatedRow[]).filter(r => r.status === 'deleted').map(r => r.name) }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo com sucesso!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar modelo.", "error"); }
        finally { setIsLoading(false); }
    };

    const handleApplyReference = async () => {
        const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
        const manual = entries.filter(([, d]) => d.status === 'manual').map(([idx, d]) => ({ originalRow: rawRows[parseInt(idx)], corrected: { date: d.date, name: d.name, amount: d.amount } }));
        if (manual.length === 0) return showToast("Edite uma linha primeiro.", "error");
        setIsLearning(true);
        try {
            const aiResults = await learnAndTransformFile(rawRows.map(r => r.map(c => c.trim())), manual);
            const newTreated = { ...treatedRows };
            aiResults.forEach((res: any) => {
                const idx = res.originalIndex;
                if (newTreated[idx] && newTreated[idx].status !== 'manual' && newTreated[idx].status !== 'deleted') {
                    newTreated[idx] = { date: res.date, name: res.name.replace('[suspeito] ', ''), amount: res.amount, status: res.name.includes('[suspeito]') ? 'suspect' : 'original' };
                }
            });
            setTreatedRows(newTreated);
            showToast("IA treinada!", "success");
        } catch (error) { showToast("Erro no treino.", "error"); }
        finally { setIsLearning(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) {
            target.current.scrollTop = source.current.scrollTop;
        }
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                {/* Header */}
                <div className="flex items-center justify-between px-10 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white/80 dark:bg-slate-900/80">
                    <div className="flex items-center gap-5">
                        <div className="p-3.5 rounded-2xl text-white bg-gradient-to-br from-indigo-600 to-violet-700 shadow-xl">
                            <BrainIcon className="w-7 h-7" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Laboratório de Layouts</h3>
                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-0.5">{initialFile?.fileName}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest shadow-xl transition-all active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar Modelo
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                            <XMarkIcon className="w-8 h-8" />
                        </button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-[#F1F5F9] dark:bg-[#020610]">

                    {/* ESQUERDA: ARQUIVO REAL (Fiel e Copiável) */}
                    <div className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14]">

                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Documento Original Real</span>
                            </div>

                            <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-brand-blue dark:text-white shadow-md' : 'text-slate-400'}`}>Visualização Real</button>
                                <button onClick={() => setViewMode('cells')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-brand-blue dark:text-white shadow-md' : 'text-slate-400'}`}>Modo Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-hidden relative">
                            {viewMode === 'original' ? (
                                <div className="h-full w-full overflow-auto custom-scrollbar">
                                    {isPdf && initialFile?.rawFile ? (
                                        <PDFRenderer file={initialFile.rawFile} />
                                    ) : isExcel && excelHtml ? (
                                        <div className="p-8">
                                            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-300 dark:border-slate-700 overflow-auto excel-preview select-all">
                                                <div dangerouslySetInnerHTML={{ __html: excelHtml }} />
                                            </div>
                                            <style>{`
                                                .excel-preview table { border-collapse: collapse; width: 100%; font-family: sans-serif; font-size: 11px; }
                                                .excel-preview td { border: 1px solid #e2e8f0; padding: 8px 12px; white-space: nowrap; }
                                                .dark .excel-preview td { border-color: #334155; color: #cbd5e1; }
                                                .excel-preview tr:nth-child(even) { background-color: #f8fafc; }
                                                .dark .excel-preview tr:nth-child(even) { background-color: #0f172a; }
                                            `}</style>
                                        </div>
                                    ) : (
                                        <div className="p-10">
                                            <pre className="text-xs font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-10 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 leading-relaxed selection:bg-brand-blue selection:text-white tab-size-4">
                                                {initialFile?.content}
                                            </pre>
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="h-full overflow-auto bg-white dark:bg-slate-900 custom-scrollbar">
                                    <table className="w-full text-[11px] border-collapse">
                                        <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b border-slate-200">
                                            <tr>
                                                <th className="w-12 px-3 py-2 text-center text-[9px] text-slate-400 border-r border-slate-200 uppercase font-black">#</th>
                                                {rawRows[0]?.map((_, i) => (
                                                    <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase tracking-tighter border-r border-slate-200 min-w-[150px]">Col {i+1}</th>
                                                ))}
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {rawRows.map((row, idx) => (
                                                <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group transition-all cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-800/50'}`}>
                                                    <td className={`text-center font-mono text-[10px] font-bold py-2 border-r border-slate-200 ${referenceRowIdx === idx ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 bg-slate-50 dark:bg-slate-800/50'}`}>{idx + 1}</td>
                                                    {row.map((cell, cIdx) => (
                                                        <td key={cIdx} className={`px-3 py-2 border-r border-slate-100 dark:border-slate-800 last:border-0 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] ${treatedRows[idx]?.status === 'deleted' ? 'opacity-30 line-through' : 'text-slate-500 dark:text-slate-400'}`}>
                                                            {cell || <span className="opacity-10 italic">---</span>}
                                                        </td>
                                                    ))}
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* DIREITA: INTERPRETADO PELA IA */}
                    <div className="flex-1 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] relative z-20">
                        <div className="px-8 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                            <div className="flex items-center gap-2">
                                <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Extração Inteligente da IA</span>
                            </div>
                            <button onClick={handleApplyReference} disabled={isLearning} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">
                                {isLearning ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />}
                                Treinar Motor
                            </button>
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b border-slate-200">
                                    <tr>
                                        <th className="px-6 py-4 text-left w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificação</th>
                                        <th className="px-6 py-4 text-right w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-6 py-4 w-12 text-center"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                    {rawRows.map((_, idx) => {
                                        const row = treatedRows[idx];
                                        if (!row) return null;
                                        const isDeleted = row.status === 'deleted';
                                        const isSuspect = row.status === 'suspect';
                                        const val = parseFloat(row.amount.replace(',', '.'));

                                        return (
                                            <tr key={idx} className={`transition-colors h-[48px] group ${referenceRowIdx === idx ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : isDeleted ? 'bg-slate-50/50 dark:bg-slate-900/20 grayscale' : isSuspect ? 'bg-amber-50/30' : ''}`}>
                                                <td className="px-6 py-0">
                                                    <input type="text" value={row.date} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], date: e.target.value, status: 'manual'}}))} className="w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold text-slate-600 dark:text-slate-400" />
                                                </td>
                                                <td className="px-6 py-0 flex items-center gap-3">
                                                    {isSuspect && <ExclamationTriangleIcon className="w-4 h-4 text-amber-500 shrink-0" />}
                                                    <input type="text" value={row.name} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], name: e.target.value, status: 'manual'}}))} className={`w-full bg-transparent border-none outline-none text-[12px] font-black ${isDeleted ? 'line-through' : row.status === 'manual' ? 'text-indigo-600' : 'text-slate-900 dark:text-white'}`} />
                                                </td>
                                                <td className="px-6 py-0">
                                                    <input type="text" value={row.amount} onChange={(e) => setTreatedRows(p => ({...p, [idx]: {...p[idx], amount: e.target.value, status: 'manual'}}))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[12px] font-black ${val < 0 ? 'text-red-600' : 'text-emerald-600'}`} />
                                                </td>
                                                <td className="px-4 py-0 text-center">
                                                    <button onClick={() => setTreatedRows(p => ({...p, [idx]: {...p[idx], status: p[idx].status === 'deleted' ? 'manual' : 'deleted'}}))} className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100">
                                                        {isDeleted ? <ArrowPathIcon className="w-4 h-4 text-emerald-500" /> : <TrashIcon className="w-4 h-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    MagnifyingGlassIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted';
}

// Componente para renderizar o PDF página por página de forma fiel e copiável
const PDFRenderer: React.FC<{ file: Blob }> = ({ file }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [pages, setPages] = useState<number[]>([]);
    const [pdfDoc, setPdfDoc] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadPdf = async () => {
            try {
                const pdfjsLib = (window as any).pdfjsLib;
                if (!pdfjsLib) return;

                const arrayBuffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
                const pdf = await loadingTask.promise;
                setPdfDoc(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
                setLoading(false);
            } catch (err) {
                console.error("Erro ao carregar PDF:", err);
            }
        };
        loadPdf();
    }, [file]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-3">
            <ArrowPathIcon className="w-8 h-8 animate-spin" />
            <span className="text-xs font-bold uppercase tracking-widest">Renderizando PDF...</span>
        </div>
    );

    return (
        <div className="flex flex-col gap-8 p-8 bg-slate-200 dark:bg-slate-950 min-h-full items-center">
            {pages.map(pageNum => (
                <PDFPage key={pageNum} pdfDoc={pdfDoc} pageNum={pageNum} />
            ))}
        </div>
    );
};

const PDFPage: React.FC<{ pdfDoc: any; pageNum: number }> = ({ pdfDoc, pageNum }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const textLayerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const renderPage = async () => {
            const page = await pdfDoc.getPage(pageNum);
            const viewport = page.getViewport({ scale: 1.5 });
            const canvas = canvasRef.current;
            if (!canvas) return;

            const context = canvas.getContext('2d');
            canvas.height = viewport.height;
            canvas.width = viewport.width;

            // Renderizar Visual
            await page.render({ canvasContext: context, viewport }).promise;

            // Renderizar Camada de Texto para Cópia (Copiável!)
            if (textLayerRef.current) {
                const textContent = await page.getTextContent();
                const pdfjsLib = (window as any).pdfjsLib;
                textLayerRef.current.innerHTML = '';
                textLayerRef.current.style.height = `${viewport.height}px`;
                textLayerRef.current.style.width = `${viewport.width}px`;

                await pdfjsLib.renderTextLayer({
                    textContent,
                    container: textLayerRef.current,
                    viewport,
                    enhanceTextSelection: true
                }).promise;
            }
        };
        renderPage();
    }, [pdfDoc, pageNum]);

    return (
        <div className="relative shadow-2xl bg-white border border-slate-300 dark:border-slate-800 rounded-sm overflow-hidden">
            <canvas ref={canvasRef} />
            <div 
                ref={textLayerRef} 
                className="absolute inset-0 pointer-events-auto textLayer"
                style={{ opacity: 0.2 }} // Deixamos um pouco visível para debugar se necessário, 0 para produção
            />
            {/* CSS necessário para a camada de texto do PDF.js */}
            <style>{`
                .textLayer { position: absolute; left: 0; top: 0; right: 0; bottom: 0; overflow: hidden; opacity: 0.1; line-height: 1.0; transform-origin: 0 0; }
                .textLayer span { color: transparent; position: absolute; white-space: pre; cursor: text; transform-origin: 0% 0%; }
                .textLayer ::selection { background: rgba(0, 82, 204, 0.3); }
            `}</style>
        </div>
    );
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<Record<number, TreatedRow>>({});
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isLearning, setIsLearning] = useState(false);
    const [isInitialInfering, setIsInitialInfering] = useState(false);
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    useEffect(() => {
        if (!initialFile) return;

        // Processamento para o modo Células
        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initialTreated: Record<number, TreatedRow> = {};
            parsed.forEach((_, idx) => {
                initialTreated[idx] = { date: '', name: '[carregando...]', amount: '0,00', status: 'unrecognized' };
            });
            setTreatedRows(initialTreated);
            triggerInitialInference(parsed);
        }

        // Processamento para o modo Excel Visual
        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const html = XLSX.utils.sheet_to_html(workbook.Sheets[workbook.SheetNames[0]]);
                setExcelHtml(html);
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        setIsInitialInfering(true);
        try {
            const sample = rows.map((r, i) => ({ row: r.map(c => c.trim()), index: i })).slice(0, 60);
            const initialGuess = await performInitialInference(sample.map(s => s.row));

            setTreatedRows(prev => {
                const newTreated = { ...prev };
                initialGuess.forEach((res: any, idx: number) => {
                    const originalIdx = sample[idx]?.index;
                    if (originalIdx !== undefined) {
                        newTreated[originalIdx] = {
                            date: res.date,
                            name: res.name.replace('[suspeito] ', ''),
                            amount: res.amount,
                            status: res.name.includes('[suspeito]') ? 'suspect' : 'inferred'
                        };
                    }
                });
                return newTreated;
            });
        } catch (e) {
            console.error("Erro IA:", e);
        } finally {
            setIsInitialInfering(false);
        }
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
                const manual = entries.find(([, d]) => d.status === 'manual');
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: manual ? rawRows[parseInt(manual[0])].findIndex(c => c.includes(manual[1].date.split('-')[2])) : 0,
                        descriptionColumnIndex: 1, amountColumnIndex: 2, skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { ignoredKeywords: customIgnoreKeywords, rowFilters: (Object.values(treatedRows) as TreatedRow[]).filter(r => r.status === 'deleted').map(r => r.name) }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo com sucesso!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar modelo.", "error"); }
        finally { setIsLoading(false); }
    };

    const handleApplyReference = async () => {
        const entries = Object.entries(treatedRows) as Array<[string, TreatedRow]>;
        const manual = entries.filter(([, d]) => d.status === 'manual').map(([idx, d]) => ({ originalRow: rawRows[parseInt(idx)], corrected: { date: d.date, name: d.name, amount: d.amount } }));
        if (manual.length === 0) return showToast("Edite uma linha primeiro.", "error");
        setIsLearning(true);
        try {
            const aiResults = await learnAndTransformFile(rawRows.map(r => r.map(c => c.trim())), manual);
            const newTreated = { ...treatedRows };
            aiResults.forEach((res: any) => {
                const idx = res.originalIndex;
                if (newTreated[idx] && newTreated[idx].status !== 'manual' && newTreated[idx].status !== 'deleted') {
                    newTreated[idx] = { date: res.date, name: res.name.replace('[suspeito] ', ''), amount: res.amount, status: res.name.includes('[suspeito]') ? 'suspect' : 'original' };
                }
            });
            setTreatedRows(newTreated);
            showToast("IA treinada!", "success");
        } catch (error) { showToast("Erro no treino.", "error"); }
        finally { setIsLearning(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) {
            target.current.scrollTop = source.current.scrollTop;
        }
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

