                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest shadow-xl transition-all active:scale-95">
