                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar
