import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger, Metrics } from './monitoringService';

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * LABORATÓRIO: Inferência Inicial
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    // Enviamos as linhas com seus índices originais para a IA não se perder
    const indexedRows = rawRows.slice(0, 60).map((row, index) => ({ index, data: row }));

    const instructions = `
        Você é o analista sênior do "Laboratório de Arquivos Inteligente".
        Sua tarefa é mapear dados brutos para colunas financeiras (Data, Nome, Valor).

        REGRAS DE VALOR (VALOR):
        1. Se houver múltiplas colunas numéricas, escolha a de MENOR magnitude média (transação, não saldo).
        2. Débitos devem ser convertidos para números NEGATIVOS.
        3. Remova símbolos de moeda (R$, $, etc).

        REGRAS DE CONTROLE (IMPORTANTE):
        1. Identifique linhas de SALDO ANTERIOR, TOTAL, RESUMO ou RODAPÉS.
        2. NÃO EXCLUA estas linhas. Retorne-as no JSON.
        3. Para estas linhas, adicione o prefixo "[suspeito] " ao nome.

        REGRAS GERAIS:
        1. Normalize datas para YYYY-MM-DD.
        2. Mantenha a ordem original rigorosamente usando o 'originalIndex' fornecido na entrada.

        RETORNE: Array JSON com objects: date (YYYY-MM-DD), name, amount, originalIndex.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Analise estas linhas indexadas e mapeie os campos. MANTENHA O originalIndex:\n\n${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    } catch (error) {
        Logger.error("Initial AI Inference failed", error);
        return [];
    }
};

/**
 * MOTOR DE APRENDIZADO REFINADO
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    // Preparamos o dataset indexado para processamento
    const indexedRows = rawRows.slice(0, 100).map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO REAL DE TREINAMENTO #${i + 1}:
        - Entrada Bruta: ${JSON.stringify(ex.originalRow)}
        - O que eu quero (VOCÊ DEVE IMITAR ISSO):
            Data: "${ex.corrected.date}"
            Nome: "${ex.corrected.name}"
            Valor: "${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        Você é o motor de inteligência do "Laboratório de Arquivos".
        Sua missão é deduzir a lógica de extração a partir dos EXEMPLOS REAIS fornecidos pelo usuário.

        MANDATOS:
        1. Observe quais colunas o usuário escolheu nos exemplos e aplique em todas as outras linhas.
        2. Se o usuário removeu termos específicos (como "PIX", "TARIFA", datas no meio do texto), você DEVE remover também.
        3. Identifique padrões de "lixo" ou "saldos" baseado no que o usuário corrigiu.
        4. MANTENHA O originalIndex de cada linha enviada na resposta.

        BASE DE CONHECIMENTO DO USUÁRIO:
        ${examplesPrompt}

        TAREFA: Transforme as linhas indexadas seguindo o padrão dos exemplos. Se uma linha for um saldo/total, use "[suspeito]" no nome.
        RETORNE: array JSON com date (YYYY-MM-DD), name, amount, originalIndex.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Processe estas linhas indexadas usando o treinamento fornecido:\n\n${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
