// Auxiliares de formatação BR
const formatToBRDate = (isoDate: string) => {
    if (!isoDate || !isoDate.includes('-')) return isoDate;
    const [y, m, d] = isoDate.split('-');
    return `${d}/${m}/${y}`;
};

const parseFromBRDate = (brDate: string) => {
    if (!brDate || !brDate.includes('/')) return brDate;
    const [d, m, y] = brDate.split('/');
    if (!d || !m || !y) return brDate;
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
};

const formatToBRAmount = (amount: string | number) => {
    const val = typeof amount === 'string' ? parseFloat(amount) : amount;
    if (isNaN(val)) return amount.toString();
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const parseFromBRAmount = (brValue: string) => {
    if (!brValue) return "0.00";
    return brValue.replace(/\./g, '').replace(',', '.');
};

// Componente PDFRenderer
const PDFRenderer: React.FC<{ file: Blob }> = ({ file }) => {
    const [pages, setPages] = useState<number[]>([]);
    const [pdfDoc, setPdfDoc] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadPdf = async () => {
            try {
                const pdfjsLib = (window as any).pdfjsLib;
                if (!pdfjsLib) return;
                const arrayBuffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
                const pdf = await loadingTask.promise;
                setPdfDoc(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
                setLoading(false);
            } catch (err) { console.error(err); }
        };
        loadPdf();
    }, [file]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-3">
            <ArrowPathIcon className="w-8 h-8 animate-spin" />
            <span className="text-xs font-bold uppercase tracking-widest">Renderizando PDF...</span>
        </div>
    );

    return (
        <div className="flex flex-col gap-8 p-8 bg-slate-200 dark:bg-slate-950 min-h-full items-center">
            {pages.map(pageNum => <PDFPage key={pageNum} pdfDoc={pdfDoc} pageNum={pageNum} />)}
        </div>
    );
};

const PDFPage: React.FC<{ pdfDoc: any; pageNum: number }> = ({ pdfDoc, pageNum }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const textLayerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const renderPage = async () => {
            const page = await pdfDoc.getPage(pageNum);
            const viewport = page.getViewport({ scale: 1.5 });
            const canvas = canvasRef.current;
            if (!canvas) return;
            const context = canvas.getContext('2d');
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;

            if (textLayerRef.current) {
                const textContent = await page.getTextContent();
                const pdfjsLib = (window as any).pdfjsLib;
                textLayerRef.current.innerHTML = '';
                await pdfjsLib.renderTextLayer({ textContent, container: textLayerRef.current, viewport, enhanceTextSelection: true }).promise;
            }
        };
        renderPage();
    }, [pdfDoc, pageNum]);

    return (
        <div className="relative shadow-2xl bg-white border border-slate-300 rounded-sm overflow-hidden">
            <canvas ref={canvasRef} />
            <div ref={textLayerRef} className="absolute inset-0 pointer-events-auto textLayer" />
            <style>{`
                .textLayer { position: absolute; left: 0; top: 0; right: 0; bottom: 0; overflow: hidden; opacity: 0.1; line-height: 1.0; transform-origin: 0 0; }
                .textLayer span { color: transparent; position: absolute; white-space: pre; cursor: text; transform-origin: 0% 0%; }
                .textLayer ::selection { background: rgba(0, 82, 204, 0.3); }
            `}</style>
        </div>
    );
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<TreatedRow[]>([]);
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isLearning, setIsLearning] = useState(false);
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    // Helper para limpar nomes usando as palavras-chave do usuário
    const cleanName = (name: string) => cleanTransactionDescriptionForDisplay(name, customIgnoreKeywords);

    useEffect(() => {
        if (!initialFile) return;

        const lines = initialFile.content.split(/\r?\n/);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initial = parsed.slice(0, 50).map((_, i) => ({
                id: `row-${i}`,
                originalIndex: i,
                date: '',
                name: '[processando...]',
                amount: '0,00',
                status: 'unrecognized' as const
            }));
            setTreatedRows(initial);
            triggerInitialInference(parsed);
        }

        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array', cellNF: true, cellText: true });
                const sheet = workbook.Sheets[workbook.SheetNames[0]];
                Object.keys(sheet).forEach(c => {
                    const cell = sheet[c];
                    if (cell && cell.t === 'n' && !cell.w) cell.w = cell.v.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
                });
                setExcelHtml(XLSX.utils.sheet_to_html(sheet));
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile, isExcel]);

    const triggerInitialInference = async (rows: string[][]) => {
        try {
            const sample = rows.map((r, i) => ({ row: r.map(c => c.trim()), index: i })).slice(0, 60);
            const initialGuess = await performInitialInference(rows);

            setTreatedRows(prev => {
                const next = [...prev];
                initialGuess.forEach((res: any) => {
                    const targetIdx = next.findIndex(r => r.originalIndex === res.originalIndex);
                    if (targetIdx !== -1) {
                        const rawName = res.name.replace(/\[suspeito\]/gi, '').trim();
                        const isSuspect = res.name.toLowerCase().includes('[suspeito]');
                        next[targetIdx] = {
                            ...next[targetIdx],
                            date: res.date,
                            name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName),
                            amount: res.amount,
                            status: isSuspect ? 'suspect' : 'inferred'
                        };
                    }
                });
                return next;
            });
        } catch (e) { console.error(e); }
    };

    const handleAddManualRow = () => {
        const newRow: TreatedRow = {
            id: `manual-${Date.now()}`,
            date: new Date().toISOString().split('T')[0],
            name: '',
            amount: '0.00',
            status: 'manual'
        };
        setTreatedRows(prev => [newRow, ...prev]);
    };

    const updateRow = (id: string, field: keyof TreatedRow, value: any) => {
        setTreatedRows(prev => prev.map(r => {
            if (r.id === id) {
                const finalValue = field === 'name' ? cleanName(value) : value;
                return { ...r, [field]: finalValue, status: 'manual' };
            }
            return r;
        }));
    };

    const handleApplyReference = async () => {
        const manual = treatedRows.filter(r => r.status === 'manual' && r.originalIndex !== undefined).map(r => ({
            originalRow: rawRows[r.originalIndex!],
            corrected: { date: r.date, name: r.name, amount: r.amount }
        }));
        if (manual.length === 0) return showToast("Edite uma linha original primeiro.", "error");

        setIsLearning(true);
        try {
            const aiResults = await learnAndTransformFile(rawRows, manual);
            const next = [...treatedRows];

            aiResults.forEach((res: any) => {
                const targetIdx = next.findIndex(r => r.originalIndex === Number(res.originalIndex));
                if (targetIdx !== -1 && next[targetIdx].status !== 'manual') {
                    const rawName = res.name.replace(/\[suspeito\]/gi, '').trim();
                    const isSuspect = res.name.toLowerCase().includes('[suspeito]');
                    next[targetIdx] = { 
                        ...next[targetIdx], 
                        date: res.date, 
                        name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName), 
                        amount: res.amount, 
                        status: isSuspect ? 'suspect' : 'original' 
                    };
                }
            });
            setTreatedRows(next);
            showToast("IA treinada com sucesso!", "success");
        } catch (error) { showToast("Erro no motor de aprendizado.", "error"); }
        finally { setIsLearning(false); }
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2,
                        skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { ignoredKeywords: customIgnoreKeywords, rowFilters: treatedRows.filter(r => r.status === 'deleted').map(r => r.name) }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar.", "error"); }
        finally { setIsLoading(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) target.current.scrollTop = source.current.scrollTop;
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                {/* Header Principal */}
                <div className="flex items-center justify-between px-10 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0">
                    <div className="flex items-center gap-5">
                        <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-xl"><BrainIcon className="w-7 h-7" /></div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white">Laboratório de Layouts</h3>
                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">{initialFile?.fileName}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400"><XMarkIcon className="w-8 h-8" /></button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-[#F1F5F9] dark:bg-[#020610]">

                    {/* ESQUERDA: DOCUMENTO ORIGINAL (50%) */}
                    <div className="basis-1/2 shrink-0 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14] min-w-0">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Documento Real</span>
                            </div>
                            <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Visualização Real</button>
                                <button onClick={() => setViewMode('cells')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Modo Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            {viewMode === 'original' ? (
                                isPdf && initialFile?.rawFile ? <PDFRenderer file={initialFile.rawFile} /> :
                                isExcel && excelHtml ? (
                                    <div className="p-8">
                                        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-300 overflow-auto excel-preview select-all">
                                            <div dangerouslySetInnerHTML={{ __html: excelHtml }} />
                                        </div>
                                        <style>{`
                                            .excel-preview table { border-collapse: collapse; width: 100%; font-family: sans-serif; font-size: 11px; }
                                            .excel-preview td { border: 1px solid #e2e8f0; padding: 10px; white-space: nowrap; }
                                            .dark .excel-preview td { border-color: #334155; color: #cbd5e1; }
                                        `}</style>
                                    </div>
                                ) : <div className="p-10"><pre className="text-xs font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-10 rounded-2xl shadow-xl leading-relaxed select-all">{initialFile?.content}</pre></div>
                            ) : (
                                <table className="w-full text-[11px] border-collapse bg-white dark:bg-slate-900">
                                    <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b">
                                        <tr>
                                            <th className="w-12 px-3 py-2 text-center text-slate-400 uppercase font-black border-r">#</th>
                                            {rawRows[0]?.map((_, i) => <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase border-r min-w-[150px]">Col {i+1}</th>)}
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {rawRows.map((row, idx) => (
                                            <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50'}`}>
                                                <td className={`text-center font-mono text-[10px] font-bold py-2 border-r ${referenceRowIdx === idx ? 'bg-indigo-600 text-white' : 'text-slate-400 bg-slate-50'}`}>{idx + 1}</td>
                                                {row.map((cell, cIdx) => <td key={cIdx} className="px-3 py-2 border-r border-slate-100 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] text-slate-500">{cell || '---'}</td>)}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>

                    {/* DIREITA: INTELIGÊNCIA EDITÁVEL (50%) */}
                    <div className="basis-1/2 shrink-0 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] relative z-20 min-w-0">
                        <div className="px-8 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                            <div className="flex items-center gap-2">
                                <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Inteligência da IA</span>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={handleAddManualRow} className="flex items-center gap-2 px-5 py-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-full text-[10px] font-black uppercase transition-all shadow-sm">
                                    <PlusCircleIcon className="w-4 h-4" /> Nova Linha
                                </button>
                                <button onClick={handleApplyReference} disabled={isLearning} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">
                                    {isLearning ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} Treinar Motor
                                </button>
                            </div>
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b">
                                    <tr>
                                        <th className="px-6 py-4 text-left w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificação (Limpeza Ativa)</th>
                                        <th className="px-6 py-4 text-right w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-6 py-4 w-12"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                    {treatedRows.map((row) => {
                                        const isDeleted = row.status === 'deleted';
                                        const isSuspect = row.status === 'suspect';
                                        const valStr = row.amount;

                                        return (
                                            <tr key={row.id} className={`transition-colors h-[48px] group ${referenceRowIdx === row.originalIndex && row.originalIndex !== undefined ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : isDeleted ? 'opacity-40 grayscale' : isSuspect ? 'bg-amber-50/30' : ''}`}>
                                                <td className="px-6 py-0">
                                                    <input 
                                                        type="text" 
                                                        value={formatToBRDate(row.date)} 
                                                        onChange={(e) => updateRow(row.id, 'date', parseFromBRDate(e.target.value))} 
                                                        className="w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold text-slate-600 dark:text-slate-400" 
                                                        placeholder="DD/MM/AAAA"
                                                    />
                                                </td>
                                                <td className="px-6 py-0 flex items-center gap-3">
                                                    {isSuspect && <ExclamationTriangleIcon className="w-4 h-4 text-amber-500 shrink-0" />}
                                                    <input 
                                                        type="text" 
                                                        value={row.name} 
                                                        onChange={(e) => updateRow(row.id, 'name', e.target.value)} 
                                                        className={`w-full bg-transparent border-none outline-none text-[12px] font-black ${isDeleted ? 'line-through' : 'text-slate-900 dark:text-white'} focus:ring-1 focus:ring-indigo-500/30 rounded px-1`} 
                                                        placeholder="Cole ou digite a identificação..."
                                                    />
                                                </td>
                                                <td className="px-6 py-0">
                                                    <input 
                                                        type="text" 
                                                        value={formatToBRAmount(row.amount)} 
                                                        onChange={(e) => updateRow(row.id, 'amount', parseFromBRAmount(e.target.value))} 
                                                        className={`w-full bg-transparent border-none outline-none text-right font-mono text-[12px] font-black ${valStr.startsWith('-') ? 'text-red-600' : 'text-emerald-600'}`} 
                                                        placeholder="0,00"
                                                    />
                                                </td>
                                                <td className="px-4 py-0 text-center">
                                                    <button onClick={() => updateRow(row.id, 'status', row.status === 'deleted' ? 'manual' : 'deleted')} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                                        {isDeleted ? <ArrowPathIcon className="w-4 h-4 text-emerald-500" /> : <TrashIcon className="w-4 h-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    PlusCircleIcon,
    MagnifyingGlassIcon,
    BoltIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint, cleanTransactionDescriptionForDisplay } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing';
}

// Auxiliares de formatação BR
const formatToBRDate = (isoDate: string) => {
    if (!isoDate || !isoDate.includes('-')) return isoDate;
    const [y, m, d] = isoDate.split('-');
    return `${d}/${m}/${y}`;
};

const parseFromBRDate = (brDate: string) => {
    if (!brDate || !brDate.includes('/')) return brDate;
    const [d, m, y] = brDate.split('/');
    if (!d || !m || !y) return brDate;
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
};

const formatToBRAmount = (amount: string | number) => {
    const val = typeof amount === 'string' ? parseFloat(amount) : amount;
    if (isNaN(val)) return amount.toString();
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const parseFromBRAmount = (brValue: string) => {
    if (!brValue) return "0.00";
    return brValue.replace(/\./g, '').replace(',', '.');
};

// Componente PDFRenderer (Mantido para fidelidade)
const PDFRenderer: React.FC<{ file: Blob }> = ({ file }) => {
    const [pages, setPages] = useState<number[]>([]);
    const [pdfDoc, setPdfDoc] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadPdf = async () => {
            try {
                const pdfjsLib = (window as any).pdfjsLib;
                if (!pdfjsLib) return;
                const arrayBuffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
                const pdf = await loadingTask.promise;
                setPdfDoc(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
                setLoading(false);
            } catch (err) { console.error(err); }
        };
        loadPdf();
    }, [file]);

    if (loading) return (
        <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-3">
            <ArrowPathIcon className="w-8 h-8 animate-spin" />
            <span className="text-xs font-bold uppercase tracking-widest">Renderizando PDF...</span>
        </div>
    );

    return (
        <div className="flex flex-col gap-8 p-8 bg-slate-200 dark:bg-slate-950 min-h-full items-center">
            {pages.map(pageNum => <PDFPage key={pageNum} pdfDoc={pdfDoc} pageNum={pageNum} />)}
        </div>
    );
};

const PDFPage: React.FC<{ pdfDoc: any; pageNum: number }> = ({ pdfDoc, pageNum }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const textLayerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const renderPage = async () => {
            const page = await pdfDoc.getPage(pageNum);
            const viewport = page.getViewport({ scale: 1.5 });
            const canvas = canvasRef.current;
            if (!canvas) return;
            const context = canvas.getContext('2d');
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;

            if (textLayerRef.current) {
                const textContent = await page.getTextContent();
                const pdfjsLib = (window as any).pdfjsLib;
                textLayerRef.current.innerHTML = '';
                await pdfjsLib.renderTextLayer({ textContent, container: textLayerRef.current, viewport, enhanceTextSelection: true }).promise;
            }
        };
        renderPage();
    }, [pdfDoc, pageNum]);

    return (
        <div className="relative shadow-2xl bg-white border border-slate-300 rounded-sm overflow-hidden">
            <canvas ref={canvasRef} />
            <div ref={textLayerRef} className="absolute inset-0 pointer-events-auto textLayer" />
            <style>{`
                .textLayer { position: absolute; left: 0; top: 0; right: 0; bottom: 0; overflow: hidden; opacity: 0.1; line-height: 1.0; transform-origin: 0 0; }
                .textLayer span { color: transparent; position: absolute; white-space: pre; cursor: text; transform-origin: 0% 0%; }
                .textLayer ::selection { background: rgba(0, 82, 204, 0.3); }
            `}</style>
        </div>
    );
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<TreatedRow[]>([]);
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isAILoading, setIsAILoading] = useState(false);
    const [progress, setProgress] = useState({ current: 0, total: 0 });
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    const cleanName = (name: string) => cleanTransactionDescriptionForDisplay(name, customIgnoreKeywords);

    useEffect(() => {
        if (!initialFile) return;

        const lines = initialFile.content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            // Limitamos o preview inicial para performance da UI, mas a IA processará em lotes
            const sampleSize = Math.min(parsed.length, 100);
            const initial = parsed.slice(0, sampleSize).map((_, i) => ({
                id: `row-${i}`,
                originalIndex: i,
                date: '',
                name: '',
                amount: '0.00',
                status: 'unrecognized' as const
            }));
            setTreatedRows(initial);
            triggerBatchInference(parsed.slice(0, 100));
        }

        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array', cellNF: true, cellText: true });
                const sheet = workbook.Sheets[workbook.SheetNames[0]];
                Object.keys(sheet).forEach(c => {
                    const cell = sheet[c];
                    if (cell && cell.t === 'n' && !cell.w) cell.w = cell.v.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
                });
                setExcelHtml(XLSX.utils.sheet_to_html(sheet));
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile, isExcel]);

    // Lógica de inferência em lotes (Chunks)
    const triggerBatchInference = async (rows: string[][]) => {
        setIsAILoading(true);
        const CHUNK_SIZE = 20;
        const total = rows.length;
        setProgress({ current: 0, total });

        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rows.slice(i, i + CHUNK_SIZE);
            const chunkIndices = Array.from({ length: chunk.length }, (_, k) => i + k);

            // Marca as linhas do lote como "em processamento"
            setTreatedRows(prev => prev.map(r => 
                r.originalIndex !== undefined && chunkIndices.includes(r.originalIndex) 
                ? { ...r, status: 'processing' as const } 
                : r
            ));

            try {
                // Passamos apenas o chunk para a IA
                const aiResults = await performInitialInference(chunk);

                setTreatedRows(prev => {
                    const next = [...prev];
                    aiResults.forEach((res: any, idx: number) => {
                        // Ajustamos o índice retornado pela IA para o índice real do arquivo
                        const realIdx = i + res.originalIndex;
                        const targetPos = next.findIndex(r => r.originalIndex === realIdx);

                        if (targetPos !== -1) {
                            const rawName = res.name.replace(/\[suspeito\]/gi, '').trim();
                            const isSuspect = res.name.toLowerCase().includes('[suspeito]');
                            next[targetPos] = {
                                ...next[targetPos],
                                date: res.date,
                                name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName),
                                amount: res.amount,
                                status: isSuspect ? 'suspect' : 'inferred'
                            };
                        }
                    });
                    return next;
                });
                setProgress(p => ({ ...p, current: Math.min(total, i + CHUNK_SIZE) }));
            } catch (e) {
                console.error("Erro no lote:", i, e);
            }
        }
        setIsAILoading(false);
    };

    const handleAddManualRow = () => {
        const newRow: TreatedRow = {
            id: `manual-${Date.now()}`,
            date: new Date().toISOString().split('T')[0],
            name: '',
            amount: '0.00',
            status: 'manual'
        };
        setTreatedRows(prev => [newRow, ...prev]);
    };

    const updateRow = (id: string, field: keyof TreatedRow, value: any) => {
        setTreatedRows(prev => prev.map(r => {
            if (r.id === id) {
                const finalValue = field === 'name' ? cleanName(value) : value;
                return { ...r, [field]: finalValue, status: 'manual' };
            }
            return r;
        }));
    };

    const handleApplyReference = async () => {
        const manual = treatedRows.filter(r => r.status === 'manual' && r.originalIndex !== undefined).map(r => ({
            originalRow: rawRows[r.originalIndex!],
            corrected: { date: r.date, name: r.name, amount: r.amount }
        }));
        if (manual.length === 0) return showToast("Edite uma linha original primeiro.", "error");

        // Treinamento também em lotes para rapidez e feedback
        setIsAILoading(true);
        const rowsToTrain = rawRows.slice(0, 100);
        const total = rowsToTrain.length;
        setProgress({ current: 0, total });

        for (let i = 0; i < total; i += 25) {
            const chunk = rowsToTrain.slice(i, i + 25);
            try {
                const aiResults = await learnAndTransformFile(chunk, manual);
                setTreatedRows(prev => {
                    const next = [...prev];
                    aiResults.forEach((res: any) => {
                        const realIdx = i + Number(res.originalIndex);
                        const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                        if (targetPos !== -1 && next[targetPos].status !== 'manual') {
                            const rawName = res.name.replace(/\[suspeito\]/gi, '').trim();
                            const isSuspect = res.name.toLowerCase().includes('[suspeito]');
                            next[targetPos] = { 
                                ...next[targetPos], 
                                date: res.date, 
                                name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName), 
                                amount: res.amount, 
                                status: isSuspect ? 'suspect' : 'original' 
                            };
                        }
                    });
                    return next;
                });
                setProgress(p => ({ ...p, current: Math.min(total, i + 25) }));
            } catch (e) { console.error(e); }
        }
        setIsAILoading(false);
        showToast("IA treinada com sucesso!", "success");
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2,
                        skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { ignoredKeywords: customIgnoreKeywords, rowFilters: treatedRows.filter(r => r.status === 'deleted').map(r => r.name) }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar.", "error"); }
        finally { setIsLoading(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) target.current.scrollTop = source.current.scrollTop;
    };

    const progressPercent = progress.total > 0 ? (progress.current / progress.total) * 100 : 0;

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in font-sans">
