import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger, Metrics } from './monitoringService';

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * LABORATÓRIO: Inferência Inicial Otimizada
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    // Indexamos as linhas para garantir que a IA devolva a referência correta
    const indexedRows = rawRows.map((row, index) => ({ originalIndex: index, data: row }));

    const instructions = `
        Analise estas linhas de um extrato bancário e extraia: Data, Nome/Descrição e Valor.

        REGRAS:
        1. Data: Converta para YYYY-MM-DD.
        2. Valor: Use ponto decimal, remova R$. Se for débito, use sinal negativo.
        3. Nome: Se a linha parecer um SALDO, TOTAL ou RESUMO, adicione o prefixo "[suspeito] ".
        4. MANTENHA O originalIndex exatamente como recebido.
        5. Se não conseguir identificar um campo, retorne "N/A" mas NUNCA omita o objeto.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Mapeie estas linhas (Formato JSON): ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    } catch (error) {
        Logger.error("Initial AI Inference failed", error);
        return [];
    }
};

/**
 * MOTOR DE APRENDIZADO REFINADO
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    const indexedRows = rawRows.map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO #${i + 1}: Entrada: ${JSON.stringify(ex.originalRow)} -> Saída desejada: Data="${ex.corrected.date}", Nome="${ex.corrected.name}", Valor="${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        Aprenda com estes exemplos e processe as novas linhas seguindo RIGOROSAMENTE o mesmo padrão de colunas e limpeza:
        ${examplesPrompt}

        MANDATOS:
        1. MANTENHA O originalIndex.
        2. Retorne JSON válido.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Processe: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    } catch (error) {
        Logger.error("AI Multi-Shot Learning failed", error);
        return [];
    }
};

export const getAISuggestion = async (
  transaction: Transaction,
  contributors: Contributor[]
): Promise<string> => {
  const ai = getAIClient();
  const contributorNames = contributors.map(c => c.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analise a transação: "${transaction.description}" contra esta lista de contribuinte: [${contributorNames}]. Responda APENAS o nome exato do contribuinte que mais se assemelha ou "Nenhuma sugestão clara".`,
      config: {
          temperature: 0.1,
          topP: 0.95,
      }
    });

    return response.text?.trim() || "Nenhuma sugestão clara";

  } catch (error) {
    Logger.error("Error calling Gemini directly", error);
    Metrics.increment('apiErrors');
    return "Erro ao contatar a IA.";
  }
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    PlusCircleIcon,
    BoltIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint, cleanTransactionDescriptionForDisplay } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel } from '../../types';
import * as XLSX from 'xlsx';

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing';
}

const formatToBRDate = (isoDate: string) => {
    if (!isoDate || !isoDate.includes('-')) return isoDate;
    const [y, m, d] = isoDate.split('-');
    return `${d}/${m}/${y}`;
};

const parseFromBRDate = (brDate: string) => {
    if (!brDate || !brDate.includes('/')) return brDate;
    const [d, m, y] = brDate.split('/');
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
};

const formatToBRAmount = (amount: string | number) => {
    const val = typeof amount === 'string' ? parseFloat(amount) : amount;
    if (isNaN(val)) return amount.toString();
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const parseFromBRAmount = (brValue: string) => {
    if (!brValue) return "0.00";
    return brValue.replace(/\./g, '').replace(',', '.');
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<TreatedRow[]>([]);
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isAILoading, setIsAILoading] = useState(false);
    const [progress, setProgress] = useState({ current: 0, total: 0 });
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    const cleanName = (name: string) => cleanTransactionDescriptionForDisplay(name, customIgnoreKeywords);

    useEffect(() => {
        if (!initialFile) return;

        const lines = initialFile.content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));

            // O Laboratório foca nas primeiras 100 linhas para TREINAMENTO
            const trainSample = parsed.slice(0, 100);
            setRawRows(trainSample);

            const initial = trainSample.map((_, i) => ({
                id: `row-${i}`,
                originalIndex: i,
                date: '',
                name: '',
                amount: '0.00',
                status: 'unrecognized' as const
            }));
            setTreatedRows(initial);
            triggerParallelInference(trainSample);
        }

        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const sheet = workbook.Sheets[workbook.SheetNames[0]];
                setExcelHtml(XLSX.utils.sheet_to_html(sheet));
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile]);

    // Processamento Paralelo para Velocidade
    const triggerParallelInference = async (rows: string[][]) => {
        setIsAILoading(true);
        const CHUNK_SIZE = 25;
        const total = rows.length;
        setProgress({ current: 0, total });

        const promises = [];
        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rows.slice(i, i + CHUNK_SIZE);
            const chunkIndices = Array.from({ length: chunk.length }, (_, k) => i + k);

            setTreatedRows(prev => prev.map(r => 
                r.originalIndex !== undefined && chunkIndices.includes(r.originalIndex) 
                ? { ...r, status: 'processing' as const } : r
            ));

            promises.push(
                performInitialInference(chunk).then(results => {
                    setTreatedRows(prev => {
                        const next = [...prev];
                        results.forEach((res: any) => {
                            const realIdx = i + res.originalIndex;
                            const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                            if (targetPos !== -1) {
                                const rawName = (res.name || '---').replace(/\[suspeito\]/gi, '').trim();
                                const isSuspect = String(res.name).toLowerCase().includes('[suspeito]');
                                next[targetPos] = {
                                    ...next[targetPos],
                                    date: res.date || '',
                                    name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName),
                                    amount: res.amount || '0.00',
                                    status: isSuspect ? 'suspect' : 'inferred'
                                };
                            }
                        });
                        return next;
                    });
                    setProgress(p => ({ ...p, current: Math.min(total, p.current + chunk.length) }));
                })
            );
        }

        await Promise.all(promises);
        setIsAILoading(false);
    };

    const updateRow = (id: string, field: keyof TreatedRow, value: any) => {
        setTreatedRows(prev => prev.map(r => {
            if (r.id === id) {
                const finalValue = field === 'name' ? cleanName(value) : value;
                return { ...r, [field]: finalValue, status: 'manual' };
            }
            return r;
        }));
    };

    const handleApplyReference = async () => {
        const manual = treatedRows.filter(r => r.status === 'manual' && r.originalIndex !== undefined).map(r => ({
            originalRow: rawRows[r.originalIndex!],
            corrected: { date: r.date, name: r.name, amount: r.amount }
        }));
        if (manual.length === 0) return showToast("Edite uma linha primeiro.", "error");

        setIsAILoading(true);
        setProgress({ current: 0, total: rawRows.length });

        const CHUNK_SIZE = 25;
        const promises = [];

        for (let i = 0; i < rawRows.length; i += CHUNK_SIZE) {
            const chunk = rawRows.slice(i, i + CHUNK_SIZE);
            promises.push(
                learnAndTransformFile(chunk, manual).then(results => {
                    setTreatedRows(prev => {
                        const next = [...prev];
                        results.forEach((res: any) => {
                            const realIdx = i + Number(res.originalIndex);
                            const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                            if (targetPos !== -1 && next[targetPos].status !== 'manual') {
                                const rawName = (res.name || '---').replace(/\[suspeito\]/gi, '').trim();
                                const isSuspect = String(res.name).toLowerCase().includes('[suspeito]');
                                next[targetPos] = { 
                                    ...next[targetPos], 
                                    date: res.date || '', 
                                    name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName), 
                                    amount: res.amount || '0.00', 
                                    status: isSuspect ? 'suspect' : 'original' 
                                };
                            }
                        });
                        return next;
                    });
                    setProgress(p => ({ ...p, current: Math.min(rawRows.length, p.current + chunk.length) }));
                })
            );
        }

        await Promise.all(promises);
        setIsAILoading(false);
        showToast("IA treinada!", "success");
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2,
                        skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { ignoredKeywords: customIgnoreKeywords, rowFilters: treatedRows.filter(r => r.status === 'deleted').map(r => r.name) }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar.", "error"); }
        finally { setIsLoading(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) target.current.scrollTop = source.current.scrollTop;
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in font-sans">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                <div className="flex items-center justify-between px-10 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900 z-50">
                    <div className="flex items-center gap-5">
                        <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-xl"><BrainIcon className="w-7 h-7" /></div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white leading-none">Laboratório de Layouts</h3>
                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1.5">{initialFile?.fileName} (Treinando 100 linhas)</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors"><XMarkIcon className="w-8 h-8" /></button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-[#F1F5F9] dark:bg-[#020610]">
                    <div className="basis-1/2 shrink-0 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14] min-w-0">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Documento Real</span>
                            </div>
                            <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Visualização Real</button>
                                <button onClick={() => setViewMode('cells')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Modo Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            {viewMode === 'original' ? (
                                isPdf && initialFile?.rawFile ? <PDFRenderer file={initialFile.rawFile} /> :
                                isExcel && excelHtml ? (
                                    <div className="p-8">
                                        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-300 overflow-auto excel-preview select-all">
                                            <div dangerouslySetInnerHTML={{ __html: excelHtml }} />
                                        </div>
                                    </div>
                                ) : <div className="p-10"><pre className="text-xs font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-10 rounded-2xl shadow-xl leading-relaxed select-all">{initialFile?.content.substring(0, 10000)}</pre></div>
                            ) : (
                                <table className="w-full text-[11px] border-collapse bg-white dark:bg-slate-900">
                                    <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b">
                                        <tr>
                                            <th className="w-12 px-3 py-2 text-center text-slate-400 uppercase font-black border-r">#</th>
                                            {rawRows[0]?.map((_, i) => <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase border-r min-w-[150px]">Col {i+1}</th>)}
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {rawRows.map((row, idx) => (
                                            <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50'}`}>
                                                <td className={`text-center font-mono text-[10px] font-bold py-2 border-r ${referenceRowIdx === idx ? 'bg-indigo-600 text-white' : 'text-slate-400 bg-slate-50'}`}>{idx + 1}</td>
                                                {row.map((cell, cIdx) => <td key={cIdx} className="px-3 py-2 border-r border-slate-100 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] text-slate-500">{cell || '---'}</td>)}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>

                    <div className="basis-1/2 shrink-0 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] relative z-20 min-w-0">
                        <div className="px-8 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col shrink-0">
                            <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-2">
                                    <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Inteligência da IA</span>
                                </div>
                                <div className="flex gap-2">
                                    <button onClick={handleApplyReference} disabled={isAILoading} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">
                                        {isAILoading ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} Treinar Motor
                                    </button>
                                </div>
                            </div>

                            {isAILoading && (
                                <div className="flex flex-col gap-1 mt-1 animate-fade-in">
                                    <div className="flex justify-between items-center text-[9px] font-black text-indigo-600 uppercase tracking-tighter">
                                        <span className="flex items-center gap-1"><BoltIcon className="w-3 h-3 animate-pulse" /> Treinando em paralelo...</span>
                                        <span>{progress.current} de {progress.total}</span>
                                    </div>
                                    <div className="h-1 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                        <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${(progress.current/progress.total)*100}%` }}></div>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b">
                                    <tr>
                                        <th className="px-6 py-4 text-left w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificação</th>
                                        <th className="px-6 py-4 text-right w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-6 py-4 w-12"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                    {treatedRows.map((row) => {
                                        const isDeleted = row.status === 'deleted';
                                        const isSuspect = row.status === 'suspect';
                                        const isProcessing = row.status === 'processing';

                                        return (
                                            <tr key={row.id} className={`h-[48px] group ${referenceRowIdx === row.originalIndex ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : isSuspect ? 'bg-amber-50/20' : ''}`}>
                                                <td className="px-6 py-0">
                                                    {isProcessing ? <div className="w-16 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded"></div> : (
                                                        <input type="text" value={formatToBRDate(row.date)} onChange={(e) => updateRow(row.id, 'date', parseFromBRDate(e.target.value))} className="w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold text-slate-600 dark:text-slate-400" />
                                                    )}
                                                </td>
                                                <td className="px-6 py-0 flex items-center gap-2">
                                                    {isProcessing ? <div className="flex-1 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded"></div> : (
                                                        <>
                                                            {isSuspect && <ExclamationTriangleIcon className="w-3.5 h-3.5 text-amber-500 shrink-0" />}
                                                            <input type="text" value={row.name} onChange={(e) => updateRow(row.id, 'name', e.target.value)} className={`w-full bg-transparent border-none outline-none text-[12px] font-black ${isDeleted ? 'line-through opacity-40' : 'text-slate-900 dark:text-white'}`} placeholder="..." />
                                                        </>
                                                    )}
                                                </td>
                                                <td className="px-6 py-0 text-right">
                                                    {isProcessing ? <div className="w-12 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded ml-auto"></div> : (
                                                        <input type="text" value={formatToBRAmount(row.amount)} onChange={(e) => updateRow(row.id, 'amount', parseFromBRAmount(e.target.value))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[12px] font-black ${parseFloat(row.amount) < 0 ? 'text-red-600' : 'text-emerald-600'}`} />
                                                    )}
                                                </td>
                                                <td className="px-4 py-0 text-center">
                                                    <button onClick={() => updateRow(row.id, 'status', isDeleted ? 'manual' : 'deleted')} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100">
                                                        <TrashIcon className="w-4 h-4" />
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useState, useEffect, useRef, useMemo, useContext } from 'react';
import { createPortal } from 'react-dom';
import { 
    XMarkIcon, 
    TableCellsIcon, 
    ArrowPathIcon,
    BrainIcon,
    AdjustmentsHorizontalIcon,
    ExclamationTriangleIcon,
    SparklesIcon,
    TrashIcon,
    FloppyDiskIcon,
    PlusCircleIcon,
    BoltIcon
} from '../Icons';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext';
import { useAuth } from '../../contexts/AuthContext';
import { learnAndTransformFile, performInitialInference } from '../../services/geminiService';
import { generateFingerprint, cleanTransactionDescriptionForDisplay } from '../../services/processingService';
import { modelService } from '../../services/modelService';
import { FileModel } from '../../types';
import * as XLSX from 'xlsx';

// Fix: Added PDFRenderer helper component to provide preview functionality for PDF documents
const PDFRenderer: React.FC<{ file: File }> = ({ file }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [numPages, setNumPages] = useState<number>(0);

    useEffect(() => {
        const renderPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib || !canvasRef.current) return;

            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setNumPages(pdf.numPages);

                const page = await pdf.getPage(1);
                const viewport = page.getViewport({ scale: 1.2 });
                const canvas = canvasRef.current;
                const context = canvas.getContext('2d');
                if (context) {
                    canvas.height = viewport.height;
                    canvas.width = viewport.width;

                    const renderContext = {
                        canvasContext: context,
                        viewport: viewport
                    };
                    await page.render(renderContext).promise;
                }
            } catch (err) {
                console.error("PDF Preview error:", err);
            }
        };

        renderPDF();
    }, [file]);

    return (
        <div className="p-8 flex flex-col items-center">
            <div className="bg-white p-2 shadow-2xl rounded-sm border border-slate-300">
                <canvas ref={canvasRef} className="max-w-full h-auto" />
            </div>
            {numPages > 1 && (
                <p className="mt-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                    Página 1 de {numPages} (Pré-visualização)
                </p>
            )}
        </div>
    );
};

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing';
}

const formatToBRDate = (isoDate: string) => {
    if (!isoDate || !isoDate.includes('-')) return isoDate;
    const [y, m, d] = isoDate.split('-');
    return `${d}/${m}/${y}`;
};

const parseFromBRDate = (brDate: string) => {
    if (!brDate || !brDate.includes('/')) return brDate;
    const [d, m, y] = brDate.split('/');
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
};

const formatToBRAmount = (amount: string | number) => {
    const val = typeof amount === 'string' ? parseFloat(amount) : amount;
    if (isNaN(val)) return amount.toString();
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const parseFromBRAmount = (brValue: string) => {
    if (!brValue) return "0.00";
    return brValue.replace(/\./g, '').replace(',', '.');
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<TreatedRow[]>([]);
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isAILoading, setIsAILoading] = useState(false);
    const [progress, setProgress] = useState({ current: 0, total: 0 });
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    const cleanName = (name: string) => cleanTransactionDescriptionForDisplay(name, customIgnoreKeywords);

    useEffect(() => {
        if (!initialFile) return;

        const lines = initialFile.content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));

            // O Laboratório foca nas primeiras 100 linhas para TREINAMENTO
            const trainSample = parsed.slice(0, 100);
            setRawRows(trainSample);

            const initial = trainSample.map((_, i) => ({
                id: `row-${i}`,
                originalIndex: i,
                date: '',
                name: '',
                amount: '0.00',
                status: 'unrecognized' as const
            }));
            setTreatedRows(initial);
            triggerParallelInference(trainSample);
        }

        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const sheet = workbook.Sheets[workbook.SheetNames[0]];
                setExcelHtml(XLSX.utils.sheet_to_html(sheet));
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile]);

    // Processamento Paralelo para Velocidade
    const triggerParallelInference = async (rows: string[][]) => {
        setIsAILoading(true);
        const CHUNK_SIZE = 25;
        const total = rows.length;
        setProgress({ current: 0, total });

        const promises = [];
        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rows.slice(i, i + CHUNK_SIZE);
            const chunkIndices = Array.from({ length: chunk.length }, (_, k) => i + k);

            setTreatedRows(prev => prev.map(r => 
                r.originalIndex !== undefined && chunkIndices.includes(r.originalIndex) 
                ? { ...r, status: 'processing' as const } : r
            ));

            promises.push(
                performInitialInference(chunk).then(results => {
                    setTreatedRows(prev => {
                        const next = [...prev];
                        results.forEach((res: any) => {
                            const realIdx = i + res.originalIndex;
                            const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                            if (targetPos !== -1) {
                                const rawName = (res.name || '---').replace(/\[suspeito\]/gi, '').trim();
                                const isSuspect = String(res.name).toLowerCase().includes('[suspeito]');
                                next[targetPos] = {
                                    ...next[targetPos],
                                    date: res.date || '',
                                    name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName),
                                    amount: res.amount || '0.00',
                                    status: isSuspect ? 'suspect' : 'inferred'
                                };
                            }
                        });
                        return next;
                    });
                    setProgress(p => ({ ...p, current: Math.min(total, p.current + chunk.length) }));
                })
            );
        }

        await Promise.all(promises);
        setIsAILoading(false);
    };

    const updateRow = (id: string, field: keyof TreatedRow, value: any) => {
        setTreatedRows(prev => prev.map(r => {
            if (r.id === id) {
                const finalValue = field === 'name' ? cleanName(value) : value;
                return { ...r, [field]: finalValue, status: 'manual' };
            }
            return r;
        }));
    };

    const handleApplyReference = async () => {
        const manual = treatedRows.filter(r => r.status === 'manual' && r.originalIndex !== undefined).map(r => ({
            originalRow: rawRows[r.originalIndex!],
            corrected: { date: r.date, name: r.name, amount: r.amount }
        }));
        if (manual.length === 0) return showToast("Edite uma linha primeiro.", "error");

        setIsAILoading(true);
        setProgress({ current: 0, total: rawRows.length });

        const CHUNK_SIZE = 25;
        const promises = [];

        for (let i = 0; i < rawRows.length; i += CHUNK_SIZE) {
            const chunk = rawRows.slice(i, i + CHUNK_SIZE);
            promises.push(
                learnAndTransformFile(chunk, manual).then(results => {
                    setTreatedRows(prev => {
                        const next = [...prev];
                        results.forEach((res: any) => {
                            const realIdx = i + Number(res.originalIndex);
                            const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                            if (targetPos !== -1 && next[targetPos].status !== 'manual') {
                                const rawName = (res.name || '---').replace(/\[suspeito\]/gi, '').trim();
                                const isSuspect = String(res.name).toLowerCase().includes('[suspeito]');
                                next[targetPos] = { 
                                    ...next[targetPos], 
                                    date: res.date || '', 
                                    name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName), 
                                    amount: res.amount || '0.00', 
                                    status: isSuspect ? 'suspect' : 'original' 
                                };
                            }
                        });
                        return next;
                    });
                    setProgress(p => ({ ...p, current: Math.min(rawRows.length, p.current + chunk.length) }));
                })
            );
        }

        await Promise.all(promises);
        setIsAILoading(false);
        showToast("IA treinada!", "success");
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2,
                        skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { ignoredKeywords: customIgnoreKeywords, rowFilters: treatedRows.filter(r => r.status === 'deleted').map(r => r.name) }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar.", "error"); }
        finally { setIsLoading(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) target.current.scrollTop = source.current.scrollTop;
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in font-sans">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                <div className="flex items-center justify-between px-10 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900 z-50">
                    <div className="flex items-center gap-5">
                        <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-xl"><BrainIcon className="w-7 h-7" /></div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white leading-none">Laboratório de Layouts</h3>
                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1.5">{initialFile?.fileName} (Treinando 100 linhas)</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Confirmar e Salvar
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors"><XMarkIcon className="w-8 h-8" /></button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-[#F1F5F9] dark:bg-[#020610]">
                    <div className="basis-1/2 shrink-0 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14] min-w-0">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Documento Real</span>
                            </div>
                            <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Visualização Real</button>
                                <button onClick={() => setViewMode('cells')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Modo Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            {viewMode === 'original' ? (
                                isPdf && initialFile?.rawFile ? <PDFRenderer file={initialFile.rawFile} /> :
                                isExcel && excelHtml ? (
                                    <div className="p-8">
                                        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-300 overflow-auto excel-preview select-all">
                                            <div dangerouslySetInnerHTML={{ __html: excelHtml }} />
                                        </div>
                                    </div>
                                ) : <div className="p-10"><pre className="text-xs font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-10 rounded-2xl shadow-xl leading-relaxed select-all">{initialFile?.content.substring(0, 10000)}</pre></div>
                            ) : (
                                <table className="w-full text-[11px] border-collapse bg-white dark:bg-slate-900">
                                    <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b">
                                        <tr>
                                            <th className="w-12 px-3 py-2 text-center text-slate-400 uppercase font-black border-r">#</th>
                                            {rawRows[0]?.map((_, i) => <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase border-r min-w-[150px]">Col {i+1}</th>)}
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {rawRows.map((row, idx) => (
                                            <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50'}`}>
                                                <td className={`text-center font-mono text-[10px] font-bold py-2 border-r ${referenceRowIdx === idx ? 'bg-indigo-600 text-white' : 'text-slate-400 bg-slate-50'}`}>{idx + 1}</td>
                                                {row.map((cell, cIdx) => <td key={cIdx} className="px-3 py-2 border-r border-slate-100 whitespace-nowrap overflow-hidden text-ellipsis max-w-[250px] text-slate-500">{cell || '---'}</td>)}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>

                    <div className="basis-1/2 shrink-0 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] relative z-20 min-w-0">
                        <div className="px-8 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col shrink-0">
                            <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-2">
                                    <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Inteligência da IA</span>
                                </div>
                                <div className="flex gap-2">
                                    <button onClick={handleApplyReference} disabled={isAILoading} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">
                                        {isAILoading ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} Treinar Motor
                                    </button>
                                </div>
                            </div>

                            {isAILoading && (
                                <div className="flex flex-col gap-1 mt-1 animate-fade-in">
                                    <div className="flex justify-between items-center text-[9px] font-black text-indigo-600 uppercase tracking-tighter">
                                        <span className="flex items-center gap-1"><BoltIcon className="w-3 h-3 animate-pulse" /> Treinando em paralelo...</span>
                                        <span>{progress.current} de {progress.total}</span>
                                    </div>
                                    <div className="h-1 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                        <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${(progress.current/progress.total)*100}%` }}></div>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b">
                                    <tr>
                                        <th className="px-6 py-4 text-left w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificação</th>
                                        <th className="px-6 py-4 text-right w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-6 py-4 w-12"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                    {treatedRows.map((row) => {
                                        const isDeleted = row.status === 'deleted';
                                        const isSuspect = row.status === 'suspect';
                                        const isProcessing = row.status === 'processing';

                                        return (
                                            <tr key={row.id} className={`h-[48px] group ${referenceRowIdx === row.originalIndex ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : isSuspect ? 'bg-amber-50/20' : ''}`}>
                                                <td className="px-6 py-0">
                                                    {isProcessing ? <div className="w-16 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded"></div> : (
                                                        <input type="text" value={formatToBRDate(row.date)} onChange={(e) => updateRow(row.id, 'date', parseFromBRDate(e.target.value))} className="w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold text-slate-600 dark:text-slate-400" />
                                                    )}
                                                </td>
                                                <td className="px-6 py-0 flex items-center gap-2">
                                                    {isProcessing ? <div className="flex-1 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded"></div> : (
                                                        <>
                                                            {isSuspect && <ExclamationTriangleIcon className="w-3.5 h-3.5 text-amber-500 shrink-0" />}
                                                            <input type="text" value={row.name} onChange={(e) => updateRow(row.id, 'name', e.target.value)} className={`w-full bg-transparent border-none outline-none text-[12px] font-black ${isDeleted ? 'line-through opacity-40' : 'text-slate-900 dark:text-white'}`} placeholder="..." />
                                                        </>
                                                    )}
                                                </td>
                                                <td className="px-6 py-0 text-right">
                                                    {isProcessing ? <div className="w-12 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded ml-auto"></div> : (
                                                        <input type="text" value={formatToBRAmount(row.amount)} onChange={(e) => updateRow(row.id, 'amount', parseFromBRAmount(e.target.value))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[12px] font-black ${parseFloat(row.amount) < 0 ? 'text-red-600' : 'text-emerald-600'}`} />
                                                    )}
                                                </td>
                                                <td className="px-4 py-0 text-center">
                                                    <button onClick={() => updateRow(row.id, 'status', isDeleted ? 'manual' : 'deleted')} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100">
                                                        <TrashIcon className="w-4 h-4" />
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { createContext, useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { usePersistentState } from '../hooks/usePersistentState';
import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';
import { Logger } from '../services/monitoringService';
import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[];
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;

    // Added missing property to align with implementation
    openLabManually: () => void;
    // Fix: Updated handleStatementUpload signature to include rawFile
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleAnalyze: (transactionId: string) => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses') => void;
    discardCurrentReport: () => void;

    // Manual Operations
    manualIdentificationTx: Transaction | null;
    bulkIdentificationTxs: Transaction[] | null;
    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => void;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => void;
    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;
    divergenceConfirmation: MatchResult | null;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;
    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);
    const reconciliation = useReconciliation({
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);

    const [summary, setSummary] = usePersistentState('identificapix-dashboard-summary-v6', {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    useEffect(() => {
        if (!user) return;
        const fetchData = async () => {
            try {
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports').select('id, name, created_at, record_count, user_id, data').eq('user_id', user.id).order('created_at', { ascending: false }),
                ]);
                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);
                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, name: r.name, createdAt: r.created_at, recordCount: r.record_count, user_id: r.user_id, 
                        data: (typeof r.data === 'string' ? JSON.parse(r.data) : r.data) as any 
                    })));
                }
            } catch (err) { Logger.error('Initial fetch failed', err); }
            finally { setIsLoading(false); setInitialDataLoaded(true); }
        };
        fetchData();
    }, [user?.id]);

    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            if (!initialDataLoaded) return;
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;
            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash, initialDataLoaded]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);
    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback((reportId: string) => {
        const report = reportManager.savedReports.find(r => r.id === reportId);
        if (!report || !report.data) return;
        const validResults = report.data.results.map(r => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
        reconciliation.setMatchResults(validResults);
        reconciliation.setReportPreviewData({
            income: groupResultsByChurch(validResults.filter(r => r.transaction.amount > 0)),
            expenses: { 'all_expenses_group': validResults.filter(r => r.transaction.amount < 0) }
        });
        reconciliation.setHasActiveSession(true); setActiveView('reports'); 
    }, [reportManager.savedReports, reconciliation, setActiveView]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);
    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);
    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);
    const closeManualIdentify = useCallback(() => { reconciliation.closeManualIdentify(); }, [reconciliation]);
    const confirmManualIdentification = useCallback((transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);
        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);
            reconciliation.closeManualIdentify(); showToast('Identificação realizada.', 'success');
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false)
    }), [referenceData, reconciliation, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, findMatchResult]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import { GoogleGenAI, Type } from "@google/genai";
import { ReceiptAnalysisResult } from "../types";
import { Logger } from "./monitoringService";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeReceipt = async (file: File): Promise<ReceiptAnalysisResult> => {
  try {
    const ai = getAIClient();

    // Converter arquivo para base64 para o Gemini
    const base64Data = await new Promise<string>((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
      reader.readAsDataURL(file);
    });

    // Fix: Updated contents structure to use { parts: [...] } for multi-modal input per SDK guidelines
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data,
            },
          },
          { text: "Analise este comprovante de PIX/Transferência. Extraia o valor, data, pagador e recebedor. Verifique se parece um documento autêntico." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isValid: { type: Type.BOOLEAN },
            amount: { type: Type.NUMBER },
            date: { type: Type.STRING },
            recipient: { type: Type.STRING },
            sender: { type: Type.STRING },
            reason: { type: Type.STRING }
          },
          required: ["isValid"]
        }
      }
    });

    // Accessed .text property directly per GenAI guidelines
    const text = response.text;
    return text ? JSON.parse(text) : { isValid: false, reason: "Falha na interpretação da IA" };

  } catch (error) {
    Logger.error("Erro ao analisar comprovante via Gemini", error);
    return {
        isValid: false,
        reason: "Erro técnico ao processar a imagem diretamente."
    } as any;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger, Metrics } from './monitoringService';

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * LABORATÓRIO: Inferência Inicial Otimizada
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    const indexedRows = rawRows.map((row, index) => ({ originalIndex: index, data: row }));

    const instructions = `
        Você é um extrator cirúrgico de dados financeiros. Sua missão é separar Transações de Ruído.

        CRITÉRIOS DE VALIDAÇÃO (MUITO IMPORTANTE):
        1. Uma linha SÓ É VÁLIDA se contiver uma DATA de movimentação e um VALOR de transação.
        2. Se a linha for: CABEÇALHO, RODAPÉ, SALDO ANTERIOR, TOTAL DO DIA ou TEXTO INFORMATIVO:
           - Retorne campos "date" e "amount" VAZIOS ("").

        REGRAS DE FORMATAÇÃO:
        1. Data: YYYY-MM-DD.
        2. Valor: Numérico puro com ponto decimal. Débitos com sinal negativo.
        3. Nome: Limpe prefixos como PIX, TED, DOC.
        4. MANTENHA O originalIndex.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Mapeie estas linhas. Se não for transação, deixe data/valor vazios: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    } catch (error) {
        Logger.error("Initial AI Inference failed", error);
        return [];
    }
};

/**
 * MOTOR DE APRENDIZADO REFINADO
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    const indexedRows = rawRows.map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO #${i + 1}: Entrada: ${JSON.stringify(ex.originalRow)} -> Saída: Data="${ex.corrected.date}", Nome="${ex.corrected.name}", Valor="${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        Aprenda o padrão do usuário e processe as linhas. 
        Se uma linha não seguir o padrão de transação (falta de data/valor nos campos corretos), deixe os campos "date" e "amount" vazios.

        MANDATOS:
        1. Siga o exemplo de limpeza de nome.
        2. MANTENHA O originalIndex.
        ${examplesPrompt}
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Processe seguindo os exemplos: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    } catch (error) {
        Logger.error("AI Multi-Shot Learning failed", error);
        return [];
    }
};

export const getAISuggestion = async (
  transaction: Transaction,
  contributors: Contributor[]
): Promise<string> => {
  const ai = getAIClient();
  const contributorNames = contributors.map(c => c.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analise a transação: "${transaction.description}" contra esta lista de contribuinte: [${contributorNames}]. Responda APENAS o nome exato do contribuinte que mais se assemelha ou "Nenhuma sugestão clara".`,
      config: {
          temperature: 0.1,
          topP: 0.95,
      }
    });

    return response.text?.trim() || "Nenhuma sugestão clara";

  } catch (error) {
    Logger.error("Error calling Gemini directly", error);
    Metrics.increment('apiErrors');
    return "Erro ao contatar a IA.";
  }
};

