 * LABORATÓRIO: Inferência Inicial Otimizada (Usando Pro para máxima precisão)
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    const indexedRows = rawRows.map((row, index) => ({ originalIndex: index, data: row }));

    const instructions = `
        VOCÊ É UM EXTRATOR FINANCEIRO DE ALTA PRECISÃO.
        SUA MISSÃO: Identificar transações reais e ignorar ruído.

        REGRAS DE OURO:
        1. FIDELIDADE TOTAL: Não invente dados. Não mude valores de linha.
        2. ANCORAGEM: O "originalIndex" que você recebe deve ser exatamente o mesmo que você devolve.
        3. FILTRO DE RUÍDO: Se a linha for cabeçalho, rodapé, saldo ou informativo, retorne "date": "" e "amount": "0.00".

        FORMATO:
        - date: YYYY-MM-DD
        - name: Descrição limpa.
        - amount: Valor numérico puro (Ex: 1250.50). Débitos devem ser negativos.
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', // Upgrade para Pro para lidar com PDFs complexos
            contents: `Mapeie exatamente estas linhas: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

/**
 * MOTOR DE APRENDIZADO REFINADO (ANÁLISE ESPACIAL E SEMÂNTICA)
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    const indexedRows = rawRows.map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO REAL #${i + 1}:
        ENTRADA BRUTA (ARRAY): ${JSON.stringify(ex.originalRow)}
        TRANSFORMAÇÃO REALIZADA PELO USUÁRIO:
        - DATA extraída: "${ex.corrected.date}"
        - NOME (Pessoa/Empresa) extraído: "${ex.corrected.name}"
        - VALOR extraído: "${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        VOCÊ É UM ALGORITMO DE EXTRAÇÃO CIRÚRGICO DE ALTA PRECISÃO.
        Sua tarefa é aprender o PADRÃO DE MAPEAMENTO baseado nos exemplos e aplicá-lo ao arquivo.

        ANÁLISE DE APRENDIZADO:
        1. IDENTIFIQUE AS COLUNAS: Veja em qual índice do array de exemplo o usuário encontrou cada dado.
        2. ENTENDA O CONTEÚDO: Se o usuário extraiu nomes de pessoas, procure por nomes similares em outras linhas no mesmo índice.
        3. LIMPEZA SEMÂNTICA: Se o usuário removeu prefixos como "PIX RECEBIDO", faça o mesmo em todas as linhas.

        ORDENS RÍGIDAS:
        - NUNCA retorne nomes vazios se houver texto na coluna de "Nome".
        - MANTENHA O originalIndex inalterado.
        - NÃO DESLOQUE DADOS ENTRE LINHAS.

        EXEMPLOS PARA TREINAMENTO:
        ${examplesPrompt}
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', // Upgrade para Pro
            contents: `PROCESSE ESTE LOTE RESPEITANDO OS ÍNDICES: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

export const getAISuggestion = async (
  transaction: Transaction,
  contributors: Contributor[]
): Promise<string> => {
  const ai = getAIClient();
  const contributorNames = contributors.map(c => c.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analise a transação: "${transaction.description}" contra esta lista de contribuinte: [${contributorNames}]. Responda APENAS o nome exato do contribuinte ou "Nenhuma sugestão clara".`,
      config: { temperature: 0 }
    });
    return response.text?.trim() || "Nenhuma sugestão clara";
  } catch (error) {
    Logger.error("Error calling Gemini directly", error);
    return "Erro ao contatar a IA.";
  }
};

