const CHUNK_SIZE = 25;
const ROWS_PER_PAGE = 50;

const PDFRenderer: React.FC<{ file: File }> = ({ file }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [numPages, setNumPages] = useState<number>(0);
    const [currentPage, setCurrentPage] = useState<number>(1);
    const [pdfInstance, setPdfInstance] = useState<any>(null);

    useEffect(() => {
        const loadPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) return;
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setNumPages(pdf.numPages);
                renderPage(pdf, 1);
            } catch (err) { console.error("PDF Load error:", err); }
        };
        loadPDF();
    }, [file]);

    const renderPage = async (pdf: any, pageNum: number) => {
        if (!pdf || !canvasRef.current) return;
        const page = await pdf.getPage(pageNum);
        const viewport = page.getViewport({ scale: 1.5 });
        const canvas = canvasRef.current;
        const context = canvas.getContext('2d');
        if (context) {
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
        }
    };

    const changePage = (offset: number) => {
        const newPage = Math.max(1, Math.min(numPages, currentPage + offset));
        if (newPage !== currentPage) {
            setCurrentPage(newPage);
            renderPage(pdfInstance, newPage);
        }
    };

    return (
        <div className="p-8 flex flex-col items-center">
            <div className="bg-white p-2 shadow-2xl rounded-sm border border-slate-300 mb-4">
                <canvas ref={canvasRef} className="max-w-full h-auto" />
            </div>
            <div className="flex items-center gap-4 bg-white dark:bg-slate-800 px-6 py-2 rounded-full shadow-lg border border-slate-200 dark:border-slate-700">
                <button 
                    onClick={() => changePage(-1)} 
                    disabled={currentPage === 1}
                    className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full disabled:opacity-30 transition-colors"
                >
                    <ChevronLeftIcon className="w-5 h-5 text-slate-600 dark:text-slate-300" />
                </button>
                <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest min-w-[120px] text-center">
                    Página {currentPage} de {numPages}
                </span>
                <button 
                    onClick={() => changePage(1)} 
                    disabled={currentPage === numPages}
                    className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full disabled:opacity-30 transition-colors"
                >
                    <ChevronRightIcon className="w-5 h-5 text-slate-600 dark:text-slate-300" />
                </button>
            </div>
        </div>
    );
};

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing' | 'invalid';
}

const formatToBRDate = (isoDate: string) => {
    if (!isoDate || !isoDate.includes('-')) return isoDate;
    const [y, m, d] = isoDate.split('-');
    return `${d}/${m}/${y}`;
};

const parseFromBRDate = (brDate: string) => {
    if (!brDate || !brDate.includes('/')) return brDate;
    const [d, m, y] = brDate.split('/');
    if (!d || !m || !y) return brDate;
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
};

const formatToBRAmount = (amount: string | number) => {
    const val = typeof amount === 'string' ? parseFloat(amount) : amount;
    if (isNaN(val)) return amount.toString();
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const parseFromBRAmount = (brValue: string) => {
    if (!brValue) return "0.00";
    return brValue.replace(/\./g, '').replace(',', '.');
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<TreatedRow[]>([]);
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isAILoading, setIsAILoading] = useState(false);
    const [progress, setProgress] = useState({ current: 0, total: 0 });
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);
    const [currentPage, setCurrentPage] = useState(1);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    const cleanName = (name: string) => cleanTransactionDescriptionForDisplay(name, customIgnoreKeywords);

    useEffect(() => {
        if (!initialFile) return;

        const lines = initialFile.content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initial = parsed.map((_, i) => ({
                id: `row-${i}`,
                originalIndex: i,
                date: '',
                name: '',
                amount: '0.00',
                status: 'processing' as const
            }));
            setTreatedRows(initial);
            triggerSequentialInference(parsed);
        }

        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const data = new Uint8Array(e.target?.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array', cellStyles: true, cellNF: true, cellDates: true });
                    const sheet = workbook.Sheets[workbook.SheetNames[0]];
                    setExcelHtml(XLSX.utils.sheet_to_html(sheet, { header: '', footer: '' }));
                } catch (err) { console.error("Excel Rendering Error:", err); }
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile, isExcel]);

    const visibleRows = useMemo(() => {
        return treatedRows.filter(r => {
            if (r.status === 'processing') return true;
            if (r.status === 'manual') return true;
            if (r.status === 'deleted') return true;
            const hasDate = r.date && r.date.trim() !== "" && r.date !== "N/A";
            const hasAmount = r.amount && r.amount !== "0.00" && r.amount !== "";
            return hasDate && hasAmount;
        });
    }, [treatedRows]);

    const totalPages = Math.ceil(visibleRows.length / ROWS_PER_PAGE);
    const paginatedRows = useMemo(() => {
        const start = (currentPage - 1) * ROWS_PER_PAGE;
        return visibleRows.slice(start, start + ROWS_PER_PAGE);
    }, [visibleRows, currentPage]);

    /**
     * MUDANÇA CRÍTICA: Processamento Sequencial para respeitar limites de RPM da API.
     */
    const triggerSequentialInference = async (rows: string[][]) => {
        setIsAILoading(true);
        const total = rows.length;
        setProgress({ current: 0, total });

        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rows.slice(i, i + CHUNK_SIZE);
            try {
                const results = await performInitialInference(chunk);
                setTreatedRows(prev => {
                    const next = [...prev];
                    results.forEach((res: any) => {
                        const realIdx = i + res.originalIndex;
                        const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                        if (targetPos !== -1) {
                            const rawName = (res.name || '').replace(/\[suspeito\]/gi, '').trim();
                            const isSuspect = String(res.name).toLowerCase().includes('[suspeito]');
                            const isValid = res.date && res.amount && res.date !== "N/A" && res.amount !== "0.00";

                            next[targetPos] = {
                                ...next[targetPos],
                                date: res.date || '',
                                name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName),
                                amount: res.amount || '0.00',
                                status: isValid ? (isSuspect ? 'suspect' : 'inferred') : 'invalid'
                            };
                        }
                    });
                    return next;
                });
                setProgress(p => ({ ...p, current: Math.min(total, i + chunk.length) }));
            } catch (err) {
                console.error("Erro no chunk sequencial:", err);
                showToast("Erro parcial na IA. Continuando...", "error");
            }
        }
        setIsAILoading(false);
    };

    const updateRow = (id: string, field: keyof TreatedRow, value: any) => {
        setTreatedRows(prev => prev.map(r => {
            if (r.id === id) {
                const finalValue = field === 'name' ? cleanName(value) : value;
                const newStatus = field === 'status' ? value : 'manual';
                return { ...r, [field]: finalValue, status: newStatus };
            }
            return r;
        }));
    };

    /**
     * MUDANÇA CRÍTICA: Treinamento Sequencial.
     */
    const handleApplyReference = async () => {
        const manual = treatedRows.filter(r => r.status === 'manual' && r.originalIndex !== undefined).map(r => ({
            originalRow: rawRows[r.originalIndex!],
            corrected: { date: r.date, name: r.name, amount: r.amount }
        }));
        if (manual.length === 0) return showToast("Edite uma linha primeiro.", "error");

        setIsAILoading(true);
        const total = rawRows.length;
        setProgress({ current: 0, total });

        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rawRows.slice(i, i + CHUNK_SIZE);
            try {
                const results = await learnAndTransformFile(chunk, manual);
                setTreatedRows(prev => {
                    const next = [...prev];
                    results.forEach((res: any) => {
                        const realIdx = i + Number(res.originalIndex);
                        const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                        if (targetPos !== -1 && next[targetPos].status !== 'manual') {
                            const isValid = res.date && res.amount && res.date !== "N/A" && res.amount !== "0.00";
                            next[targetPos] = { 
                                ...next[targetPos], 
                                date: res.date || '', 
                                name: cleanName(res.name || '---'), 
                                amount: res.amount || '0.00', 
                                status: isValid ? 'original' : 'invalid' 
                            };
                        }
                    });
                    return next;
                });
                setProgress(p => ({ ...p, current: Math.min(total, i + chunk.length) }));
            } catch (err) {
                console.error("Erro no treinamento sequencial:", err);
            }
        }

        setIsAILoading(false);
        showToast("IA treinada!", "success");
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2,
                        skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { 
                        ignoredKeywords: customIgnoreKeywords, 
                        rowFilters: treatedRows.filter(r => r.status === 'deleted').map(r => r.name) 
                    }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar.", "error"); }
        finally { setIsLoading(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) target.current.scrollTop = source.current.scrollTop;
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in font-sans">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                <div className="flex items-center justify-between px-10 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900 z-50">
                    <div className="flex items-center gap-5">
                        <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-xl"><BrainIcon className="w-7 h-7" /></div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white leading-none">Laboratório de Layouts</h3>
                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1.5">{initialFile?.fileName}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Salvar Modelo
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors"><XMarkIcon className="w-8 h-8" /></button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-[#F1F5F9] dark:bg-[#020610]">
                    <div className="basis-1/2 shrink-0 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14] min-w-0">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Documento Original</span>
                            </div>
                            <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
