/**
 * Utilitário de re-tentativa com backoff exponencial para respeitar limites de cota
 */
async function callWithRetry(fn: () => Promise<any>, retries = 3, delay = 2000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const errorMessage = error?.message?.toLowerCase() || "";
        const isQuotaError = errorMessage.includes("429") || errorMessage.includes("quota") || errorMessage.includes("rate limit");

        if (retries > 0 && isQuotaError) {
            console.warn(`[IA] Limite de cota atingido. Aguardando ${delay}ms para tentar novamente...`);
            await new Promise(r => setTimeout(r, delay));
            return callWithRetry(fn, retries - 1, delay * 2);
        }
        throw error;
    }
}

/**
 * LABORATÓRIO: Inferência Inicial Otimizada (Usando Pro para máxima precisão)
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    const indexedRows = rawRows.map((row, index) => ({ originalIndex: index, data: row }));

    const instructions = `
        VOCÊ É UM EXTRATOR FINANCEIRO DE ALTA PRECISÃO.

        CONTEXTO DO DOCUMENTO:
        O texto provém de um PDF que pode conter quebras de página.
        - IGNORE: Números de página (ex: "Página 1/10"), cabeçalhos repetidos e rodapés.
        - FLUXO CONTÍNUO: Trate todas as linhas como um único livro-caixa sequencial.

        MISSÃO: Identificar transações reais e ignorar o ruído de formatação do PDF.

        REGRAS DE OURO:
        1. FIDELIDADE TOTAL: Não invente dados. Não mude valores de linha.
        2. ANCORAGEM: O "originalIndex" deve ser imutável.
        3. FILTRO DE RUÍDO: Se a linha for cabeçalho, rodapé ou informativo, retorne "date": "" e "amount": "0.00".

        FORMATO:
        - date: YYYY-MM-DD
        - name: Descrição limpa.
        - amount: Valor numérico puro (Ex: 1250.50). Débitos devem ser negativos.
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: `Mapeie estas linhas de um fluxo contínuo: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

/**
 * MOTOR DE APRENDIZADO REFINADO (ANÁLISE ESPACIAL E SEMÂNTICA)
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    const indexedRows = rawRows.map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO REAL #${i + 1}:
        ENTRADA BRUTA: ${JSON.stringify(ex.originalRow)}
        TRANSFORMAÇÃO DESEJADA:
        - DATA: "${ex.corrected.date}"
        - NOME: "${ex.corrected.name}"
        - VALOR: "${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        VOCÊ É UM ALGORITMO DE EXTRAÇÃO CIRÚRGICO.

        ALERTA DE QUEBRA DE PÁGINA:
        O arquivo é um PDF. Se encontrar títulos de colunas ou datas/saldos repetidos entre as páginas, IGNORE-OS e mantenha o foco nas transações.

        ANÁLISE DE APRENDIZADO:
        1. LOCALIZAÇÃO: Identifique em qual posição do array bruto o usuário encontrou a data, o nome e o valor. Replicar esta posição em todas as outras linhas.
        2. SEMÂNTICA: Se o usuário extraiu nomes de pessoas (ex: "JOÃO"), continue buscando nomes nessa mesma região do texto.

        ORDENS RÍGIDAS:
        - MANTENHA O originalIndex inalterado.
        - NÃO DESLOQUE DADOS ENTRE LINHAS DIFERENTES.
        - SE A LINHA FOR RUÍDO (CABEÇALHO), RETORNE CAMPOS VAZIOS.

        EXEMPLOS DE TREINAMENTO:
        ${examplesPrompt}
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: `PROCESSE ESTE FLUXO SEQUENCIAL (RESPEITE OS ÍNDICES): ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

