/**
 * RENDERIZADOR DE PDF CONTÍNUO (SEM PÁGINAS ISOLADAS)
 */
const PDFRenderer: React.FC<{ file: File }> = ({ file }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [pages, setPages] = useState<number[]>([]);
    const [pdfInstance, setPdfInstance] = useState<any>(null);

    useEffect(() => {
        const loadPDF = async () => {
            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) return;
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
            } catch (err) { console.error("PDF Load error:", err); }
        };
        loadPDF();
    }, [file]);

    const PageCanvas: React.FC<{ pageNum: number, pdf: any }> = ({ pageNum, pdf }) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);
        useEffect(() => {
            const render = async () => {
                if (!pdf || !canvasRef.current) return;
                const page = await pdf.getPage(pageNum);
                const viewport = page.getViewport({ scale: 1.5 });
                const canvas = canvasRef.current;
                const context = canvas.getContext('2d');
                if (context) {
                    canvas.height = viewport.height;
                    canvas.width = viewport.width;
                    await page.render({ canvasContext: context, viewport }).promise;
                }
            };
            render();
        }, [pageNum, pdf]);
        return (
            <div className="bg-white p-2 shadow-xl border border-slate-200 mb-6 rounded-sm max-w-full overflow-hidden">
                <canvas ref={canvasRef} className="w-full h-auto" />
            </div>
        );
    };

    return (
        <div ref={containerRef} className="p-8 flex flex-col items-center bg-slate-200 dark:bg-slate-950/50 min-h-full">
            {pages.map(p => <PageCanvas key={p} pageNum={p} pdf={pdfInstance} />)}
            {pages.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                    <ArrowPathIcon className="w-10 h-10 animate-spin mb-4" />
                    <p className="text-xs font-bold uppercase tracking-widest">Carregando visualização completa...</p>
                </div>
            )}
        </div>
    );
};

interface FilePreprocessorModalProps {
    onClose: () => void;
    initialFile?: { content: string; fileName: string; type: string; bankId?: string; rawFile?: any } | null;
}

interface TreatedRow {
    id: string;
    originalIndex?: number;
    date: string;
    name: string;
    amount: string;
    status: 'manual' | 'inferred' | 'unrecognized' | 'original' | 'suspect' | 'deleted' | 'processing' | 'invalid';
}

const formatToBRDate = (isoDate: string) => {
    if (!isoDate || !isoDate.includes('-')) return isoDate;
    const [y, m, d] = isoDate.split('-');
    return `${d}/${m}/${y}`;
};

const parseFromBRDate = (brDate: string) => {
    if (!brDate || !brDate.includes('/')) return brDate;
    const [d, m, y] = brDate.split('/');
    if (!d || !m || !y) return brDate;
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
};

const formatToBRAmount = (amount: string | number) => {
    const val = typeof amount === 'string' ? parseFloat(amount) : amount;
    if (isNaN(val)) return amount.toString();
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const parseFromBRAmount = (brValue: string) => {
    if (!brValue) return "0.00";
    return brValue.replace(/\./g, '').replace(',', '.');
};

export const FilePreprocessorModal: React.FC<FilePreprocessorModalProps> = ({ onClose, initialFile }) => {
    const { showToast, setIsLoading } = useUI();
    const { user } = useAuth();
    const { fetchModels, customIgnoreKeywords } = useContext(AppContext);

    const [rawRows, setRawRows] = useState<string[][]>([]);
    const [treatedRows, setTreatedRows] = useState<TreatedRow[]>([]);
    const [referenceRowIdx, setReferenceRowIdx] = useState<number | null>(null);
    const [isAILoading, setIsAILoading] = useState(false);
    const [progress, setProgress] = useState({ current: 0, total: 0 });
    const [viewMode, setViewMode] = useState<'original' | 'cells'>('original');
    const [excelHtml, setExcelHtml] = useState<string | null>(null);
    const [currentPage, setCurrentPage] = useState(1);

    const leftScrollRef = useRef<HTMLDivElement>(null);
    const rightScrollRef = useRef<HTMLDivElement>(null);

    const isPdf = useMemo(() => initialFile?.fileName?.toLowerCase().endsWith('.pdf'), [initialFile]);
    const isExcel = useMemo(() => initialFile?.fileName?.toLowerCase().match(/\.(xlsx|xls)$/i), [initialFile]);

    const cleanName = (name: string) => cleanTransactionDescriptionForDisplay(name, customIgnoreKeywords);

    useEffect(() => {
        if (!initialFile) return;

        const lines = initialFile.content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length > 0) {
            let delimiter = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
            const parsed = lines.map(l => l.split(delimiter));
            setRawRows(parsed);

            const initial = parsed.map((_, i) => ({
                id: `row-${i}`,
                originalIndex: i,
                date: '',
                name: '',
                amount: '0.00',
                status: 'processing' as const
            }));
            setTreatedRows(initial);
            triggerSequentialInference(parsed);
        }

        if (isExcel && initialFile.rawFile) {
            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const data = new Uint8Array(e.target?.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array', cellStyles: true, cellNF: true, cellDates: true });
                    const sheet = workbook.Sheets[workbook.SheetNames[0]];
                    setExcelHtml(XLSX.utils.sheet_to_html(sheet, { header: '', footer: '' }));
                } catch (err) { console.error("Excel Rendering Error:", err); }
            };
            reader.readAsArrayBuffer(initialFile.rawFile);
        }
    }, [initialFile, isExcel]);

    const visibleRows = useMemo(() => {
        return treatedRows.filter(r => {
            if (r.status === 'processing') return true;
            if (r.status === 'manual') return true;
            if (r.status === 'deleted') return true;
            const hasDate = r.date && r.date.trim() !== "" && r.date !== "N/A";
            const hasAmount = r.amount && r.amount !== "0.00" && r.amount !== "";
            return hasDate && hasAmount;
        });
    }, [treatedRows]);

    const totalPages = Math.ceil(visibleRows.length / ROWS_PER_PAGE);
    const paginatedRows = useMemo(() => {
        const start = (currentPage - 1) * ROWS_PER_PAGE;
        return visibleRows.slice(start, start + ROWS_PER_PAGE);
    }, [visibleRows, currentPage]);

    const triggerSequentialInference = async (rows: string[][]) => {
        setIsAILoading(true);
        const total = rows.length;
        setProgress({ current: 0, total });

        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rows.slice(i, i + CHUNK_SIZE);
            try {
                const results = await performInitialInference(chunk);
                setTreatedRows(prev => {
                    const next = [...prev];
                    results.forEach((res: any) => {
                        const realIdx = i + res.originalIndex;
                        const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                        if (targetPos !== -1) {
                            const rawName = (res.name || '').replace(/\[suspeito\]/gi, '').trim();
                            const isSuspect = String(res.name).toLowerCase().includes('[suspeito]');
                            const isValid = res.date && res.amount && res.date !== "N/A" && res.amount !== "0.00";

                            next[targetPos] = {
                                ...next[targetPos],
                                date: res.date || '',
                                name: isSuspect ? `[suspeito] ${cleanName(rawName)}` : cleanName(rawName),
                                amount: res.amount || '0.00',
                                status: isValid ? (isSuspect ? 'suspect' : 'inferred') : 'invalid'
                            };
                        }
                    });
                    return next;
                });
                setProgress(p => ({ ...p, current: Math.min(total, i + chunk.length) }));
            } catch (err) {
                console.error("Erro no chunk sequencial:", err);
            }
        }
        setIsAILoading(false);
    };

    const updateRow = (id: string, field: keyof TreatedRow, value: any) => {
        setTreatedRows(prev => prev.map(r => {
            if (r.id === id) {
                const finalValue = field === 'name' ? cleanName(value) : value;
                const newStatus = field === 'status' ? value : 'manual';
                return { ...r, [field]: finalValue, status: newStatus };
            }
            return r;
        }));
    };

    const handleApplyReference = async () => {
        const manual = treatedRows.filter(r => r.status === 'manual' && r.originalIndex !== undefined).map(r => ({
            originalRow: rawRows[r.originalIndex!],
            corrected: { date: r.date, name: r.name, amount: r.amount }
        }));
        if (manual.length === 0) return showToast("Edite uma linha primeiro.", "error");

        setIsAILoading(true);
        const total = rawRows.length;
        setProgress({ current: 0, total });

        for (let i = 0; i < total; i += CHUNK_SIZE) {
            const chunk = rawRows.slice(i, i + CHUNK_SIZE);
            try {
                const results = await learnAndTransformFile(chunk, manual);
                setTreatedRows(prev => {
                    const next = [...prev];
                    results.forEach((res: any) => {
                        const realIdx = i + Number(res.originalIndex);
                        const targetPos = next.findIndex(r => r.originalIndex === realIdx);
                        if (targetPos !== -1 && next[targetPos].status !== 'manual') {
                            const isValid = res.date && res.amount && res.date !== "N/A" && res.amount !== "0.00";
                            next[targetPos] = { 
                                ...next[targetPos], 
                                date: res.date || '', 
                                name: cleanName(res.name || '---'), 
                                amount: res.amount || '0.00', 
                                status: isValid ? 'original' : 'invalid' 
                            };
                        }
                    });
                    return next;
                });
                setProgress(p => ({ ...p, current: Math.min(total, i + chunk.length) }));
            } catch (err) {
                console.error("Erro no treinamento sequencial:", err);
            }
        }

        setIsAILoading(false);
        showToast("IA treinada!", "success");
    };

    const handleFinalize = async () => {
        if (!user || !initialFile) return;
        setIsLoading(true);
        try {
            const fingerprint = generateFingerprint(initialFile.content);
            if (fingerprint) {
                const modelData: Omit<FileModel, 'id' | 'createdAt'> = {
                    name: `Modelo ${initialFile.fileName}`,
                    user_id: user.id, version: 1, lineage_id: `lin-${Date.now()}`, is_active: true,
                    fingerprint,
                    mapping: {
                        dateColumnIndex: 0, descriptionColumnIndex: 1, amountColumnIndex: 2,
                        skipRowsStart: 1, skipRowsEnd: 0, decimalSeparator: ',', thousandsSeparator: '.'
                    },
                    parsingRules: { 
                        ignoredKeywords: customIgnoreKeywords, 
                        rowFilters: treatedRows.filter(r => r.status === 'deleted').map(r => r.name) 
                    }
                };
                await modelService.saveModel(modelData);
                await fetchModels();
                showToast("Modelo salvo!", "success");
            }
            onClose();
        } catch (e) { showToast("Erro ao salvar.", "error"); }
        finally { setIsLoading(false); }
    };

    const syncScroll = (source: React.RefObject<HTMLDivElement>, target: React.RefObject<HTMLDivElement>) => {
        if (viewMode === 'cells' && source.current && target.current) target.current.scrollTop = source.current.scrollTop;
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-xl animate-fade-in font-sans">
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] w-full max-w-[1800px] h-[95vh] flex flex-col overflow-hidden shadow-2xl border border-white/10">

                <div className="flex items-center justify-between px-10 py-5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900 z-50">
                    <div className="flex items-center gap-5">
                        <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-xl"><BrainIcon className="w-7 h-7" /></div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white leading-none">Laboratório de Layouts</h3>
                            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1.5">{initialFile?.fileName}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleFinalize} className="flex items-center gap-2 px-8 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-full font-black text-[11px] uppercase tracking-widest transition-all shadow-lg active:scale-95">
                            <FloppyDiskIcon className="w-4 h-4" /> Salvar Modelo
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors"><XMarkIcon className="w-8 h-8" /></button>
                    </div>
                </div>

                <div className="flex-1 flex overflow-hidden bg-[#F1F5F9] dark:bg-[#020610]">
                    <div className="basis-1/2 shrink-0 flex flex-col border-r border-slate-200 dark:border-slate-800 relative bg-slate-100 dark:bg-[#080c14] min-w-0">
                        <div className="px-6 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0 z-10">
                             <div className="flex items-center gap-2">
                                <TableCellsIcon className="w-4 h-4 text-slate-500" />
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Documento Original (Completo)</span>
                            </div>
                            <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
                                <button onClick={() => setViewMode('original')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'original' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Visualização Contínua</button>
                                <button onClick={() => setViewMode('cells')} className={`px-4 py-1 rounded-full text-[9px] font-black uppercase transition-all ${viewMode === 'cells' ? 'bg-white dark:bg-slate-700 text-brand-blue shadow-md' : 'text-slate-400'}`}>Células</button>
                            </div>
                        </div>

                        <div ref={leftScrollRef} onScroll={() => syncScroll(leftScrollRef, rightScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            {viewMode === 'original' ? (
                                isPdf && initialFile?.rawFile ? <PDFRenderer file={initialFile.rawFile} /> :
                                isExcel && excelHtml ? (
                                    <div className="p-8">
                                        <div className="bg-white dark:bg-slate-50 p-6 rounded-2xl shadow-xl border border-slate-300 overflow-auto excel-container">
                                            <div dangerouslySetInnerHTML={{ __html: excelHtml }} />
                                        </div>
                                    </div>
                                ) : <div className="p-10"><pre className="text-xs font-mono text-slate-700 dark:text-slate-300 whitespace-pre bg-white dark:bg-slate-800 p-10 rounded-2xl shadow-xl leading-relaxed select-all">{initialFile?.content}</pre></div>
                            ) : (
                                <table className="w-full text-[11px] border-collapse bg-white dark:bg-slate-900">
                                    <thead className="sticky top-0 z-20 bg-slate-100 dark:bg-slate-800 border-b">
                                        <tr>
                                            <th className="w-12 px-3 py-2 text-center text-slate-400 uppercase font-black border-r">#</th>
                                            {rawRows[0]?.map((_, i) => <th key={i} className="px-3 py-2 text-left font-black text-slate-400 uppercase border-r min-w-[150px]">Col {i+1}</th>)}
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {rawRows.map((row, idx) => (
                                            <tr key={idx} onClick={() => setReferenceRowIdx(idx)} className={`group cursor-pointer ${referenceRowIdx === idx ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : 'hover:bg-slate-50'}`}>
                                                <td className={`text-center font-mono text-[10px] font-bold py-2 border-r ${referenceRowIdx === idx ? 'bg-indigo-600 text-white' : 'text-slate-400 bg-slate-50'}`}>{idx + 1}</td>
                                                {row.map((cell, cIdx) => <td key={cIdx} className="px-3 py-2 border-r border-slate-100 whitespace-nowrap text-slate-500">{cell || '---'}</td>)}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>

                    <div className="basis-1/2 shrink-0 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] relative z-20 min-w-0">
                        <div className="px-8 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col shrink-0">
                            <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-2">
                                    <AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" />
                                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">IA: Extração e Purificação</span>
                                </div>
                                <div className="flex gap-2">
                                    <button onClick={handleApplyReference} disabled={isAILoading} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">
                                        {isAILoading ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} Treinar Motor
                                    </button>
                                </div>
                            </div>

                            {isAILoading && (
                                <div className="flex flex-col gap-1 mt-1 animate-fade-in">
                                    <div className="flex justify-between items-center text-[9px] font-black text-indigo-600 uppercase tracking-tighter">
                                        <span className="flex items-center gap-1"><BoltIcon className="w-3 h-3 animate-pulse" /> Analisando fluxo contínuo do arquivo...</span>
                                        <span>{progress.current} de {progress.total}</span>
                                    </div>
                                    <div className="h-1 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                        <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${(progress.current/progress.total)*100}%` }}></div>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div ref={rightScrollRef} onScroll={() => syncScroll(rightScrollRef, leftScrollRef)} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b">
                                    <tr>
                                        <th className="px-6 py-4 text-left w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                                        <th className="px-6 py-4 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificação</th>
                                        <th className="px-6 py-4 text-right w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
                                        <th className="px-6 py-4 w-12 text-center">Ações</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                    {paginatedRows.map((row) => {
                                        const isDeleted = row.status === 'deleted';
                                        const isSuspect = row.status === 'suspect';
                                        const isProcessing = row.status === 'processing';

                                        return (
                                            <tr key={row.id} className={`h-[48px] group transition-all ${referenceRowIdx === row.originalIndex ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : isSuspect ? 'bg-amber-50/20' : ''}`}>
                                                <td className="px-6 py-0">
                                                    {isProcessing ? <div className="w-16 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded"></div> : (
                                                        <input type="text" value={formatToBRDate(row.date)} onChange={(e) => updateRow(row.id, 'date', parseFromBRDate(e.target.value))} className={`w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold ${isDeleted ? 'line-through text-slate-300' : 'text-slate-600 dark:text-slate-400'}`} />
                                                    )}
                                                </td>
                                                <td className="px-6 py-0 flex items-center gap-2">
                                                    {isProcessing ? <div className="flex-1 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded"></div> : (
                                                        <>
                                                            {isSuspect && <ExclamationTriangleIcon className="w-3.5 h-3.5 text-amber-500 shrink-0" />}
                                                            <input type="text" value={row.name} onChange={(e) => updateRow(row.id, 'name', e.target.value)} className={`w-full bg-transparent border-none outline-none text-[12px] font-black ${isDeleted ? 'line-through opacity-40 text-slate-400' : 'text-slate-900 dark:text-white'}`} placeholder="..." />
                                                        </>
                                                    )}
                                                </td>
                                                <td className="px-6 py-0 text-right">
                                                    {isProcessing ? <div className="w-12 h-3 bg-slate-100 dark:bg-slate-800 animate-pulse rounded ml-auto"></div> : (
                                                        <input type="text" value={formatToBRAmount(row.amount)} onChange={(e) => updateRow(row.id, 'amount', parseFromBRAmount(e.target.value))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[12px] font-black ${isDeleted ? 'line-through text-slate-300' : (parseFloat(row.amount) < 0 ? 'text-red-600' : 'text-emerald-600')}`} />
                                                    )}
                                                </td>
                                                <td className="px-4 py-0 text-center">
                                                    <button 
                                                        onClick={() => updateRow(row.id, 'status', isDeleted ? 'manual' : 'deleted')} 
                                                        className={`p-2 rounded-lg transition-all ${isDeleted ? 'text-emerald-500 bg-emerald-50' : 'text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100'}`}
                                                        title={isDeleted ? "Restaurar linha" : "Ignorar linha"}
                                                    >
                                                        {isDeleted ? <PlusCircleIcon className="w-4 h-4" /> : <TrashIcon className="w-4 h-4" />}
                                                    </button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                            {visibleRows.length === 0 && !isAILoading && (
                                <div className="flex flex-col items-center justify-center py-20 text-slate-400 opacity-60">
                                    <SparklesIcon className="w-12 h-12 mb-4" />
                                    <p className="text-sm font-bold uppercase tracking-widest">Nenhuma transação detectada</p>
                                    <p className="text-[10px] mt-2 text-center max-w-[250px]">O arquivo pode ser apenas cabeçalho ou metadados sem valor.</p>
                                </div>
                            )}
                        </div>

                        <div className="px-8 py-3 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/50 dark:bg-slate-900/50 shrink-0">
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                                Mostrando {visibleRows.length > 0 ? (currentPage - 1) * ROWS_PER_PAGE + 1 : 0}-{Math.min(visibleRows.length, currentPage * ROWS_PER_PAGE)} de {visibleRows.length} registros
                            </span>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={() => { setCurrentPage(p => Math.max(1, p - 1)); rightScrollRef.current?.scrollTo(0,0); }} 
                                    disabled={currentPage === 1}
                                    className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg disabled:opacity-30 transition-colors"
                                >
                                    <ChevronLeftIcon className="w-4 h-4 text-slate-600 dark:text-slate-300" />
                                </button>
                                <span className="text-[10px] font-black min-w-[50px] text-center">{currentPage} / {totalPages || 1}</span>
                                <button 
                                    onClick={() => { setCurrentPage(p => Math.min(totalPages, p + 1)); rightScrollRef.current?.scrollTo(0,0); }} 
                                    disabled={currentPage === totalPages || totalPages === 0}
                                    className="p-1.5 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg disabled:opacity-30 transition-colors"
                                >
                                    <ChevronRightIcon className="w-4 h-4 text-slate-600 dark:text-slate-300" />
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
};

import React, { useRef, useState, useEffect } from 'react';
import { UploadIcon, CheckCircleIcon, XMarkIcon } from './Icons';
import { Logger, Metrics } from '../services/monitoringService';

let pdfjsLib: any = null;
let mammoth: any = null;
let XLSX: any = null;

interface FileUploaderProps {
  title: string;
  onFileUpload: (content: string, fileName: string, rawFile: File) => void;
  id: string;
  isUploaded: boolean;
  uploadedFileName: string | null;
  disabled?: boolean;
  onDelete?: () => void;
}

export const FileUploader: React.FC<FileUploaderProps> = ({ title, onFileUpload, id, isUploaded, uploadedFileName, disabled = false, onDelete }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isParsing, setIsParsing] = useState(false);

  const ensureLibsLoaded = async () => {
    try {
        if (!pdfjsLib) {
            try {
                const pdfModule = await import('pdfjs-dist');
                const lib = pdfModule.default || pdfModule;
                if (!lib.GlobalWorkerOptions.workerSrc) {
                    const version = lib.version || '3.11.174';
                    if (String(version).startsWith('5.')) {
                        lib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${version}/build/pdf.worker.min.mjs`;
                    } else {
                        lib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${version}/pdf.worker.min.js`;
                    }
                }
                pdfjsLib = lib;
            } catch (e) {}
        }
        if (!mammoth) { try { const mod = await import('mammoth'); mammoth = mod.default || mod; } catch (e) {} }
        if (!XLSX) { try { const mod = await import('xlsx'); XLSX = mod.default || mod; } catch (e) {} }
    } catch (e) {}
  };

  useEffect(() => { ensureLibsLoaded(); }, []);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    processFile(file);
  };

  const processFile = async (file: File) => {
    setIsParsing(true);
    try {
        await ensureLibsLoaded();
        const fileNameLower = file.name.toLowerCase();
        const fileBuffer = await file.arrayBuffer();
        let csvContent = '';

        if (fileNameLower.endsWith('.pdf')) {
             if (!pdfjsLib) throw new Error("PDF lib missing");
             const loadingTask = pdfjsLib.getDocument(new Uint8Array(fileBuffer));
             const pdf = await loadingTask.promise;
             let fullText = '';
             let firstPageHeaders: string[] = []; // Cache para detectar cabeçalhos repetidos

             for (let i = 1; i <= pdf.numPages; i++) {
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const items = textContent.items as any[];

                 const lineTolerance = 2; 
                 const lineGroups: Map<number, any[]> = new Map();

                 items.forEach(item => {
                     if (!item.str || item.str.trim() === '') return;
                     const y = Math.round(item.transform[5] / lineTolerance) * lineTolerance;
                     if (!lineGroups.has(y)) lineGroups.set(y, []);
                     lineGroups.get(y)!.push(item);
                 });

                 const sortedY = Array.from(lineGroups.keys()).sort((a, b) => b - a);
                 let pageLines: string[] = [];

                 sortedY.forEach(y => {
                     const lineItems = lineGroups.get(y)!;
                     lineItems.sort((a, b) => a.transform[4] - b.transform[4]);

                     let lineStr = '';
                     let lastX = -1;
                     let lastWidth = 0;

                     lineItems.forEach(item => {
                         const x = item.transform[4];
                         if (lastX !== -1) {
                             const gap = x - (lastX + lastWidth);
                             if (gap > 3) lineStr += '\t';
                             else if (gap > 1.2) lineStr += ' ';
                         }
                         lineStr += item.str;
                         lastX = x;
                         lastWidth = item.width || 0;
                     });

                     const cleanLine = lineStr.trim();
                     if (cleanLine === '') return;

                     // Filtro Dinâmico de Cabeçalhos e Rodapés
                     const isPageIndicator = /p[áa]gina\s*\d+/i.test(cleanLine);
                     const isEmitDate = /emitido\s*em\s*\d+/i.test(cleanLine);

                     if (!isPageIndicator && !isEmitDate) {
                         // Nas páginas subsequentes, ignorar linhas idênticas ao topo da página 1 (títulos das colunas)
                         if (i === 1 && pageLines.length < 5) {
                             firstPageHeaders.push(cleanLine);
                         } else if (i > 1 && pageLines.length < 5 && firstPageHeaders.includes(cleanLine)) {
                             return; // Pula cabeçalho repetido
                         }
                         pageLines.push(lineStr);
                     }
                 });
                 fullText += pageLines.join('\n') + '\n';
             }
             csvContent = fullText;
        } else if (fileNameLower.endsWith('.docx')) {
            if (!mammoth) throw new Error("Word lib missing");
            const result = await mammoth.extractRawText({ arrayBuffer: fileBuffer });
            csvContent = result.value;
        } else if (fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls')) {
            if (!XLSX) throw new Error("Excel lib missing");
            const workbook = XLSX.read(new Uint8Array(fileBuffer), { type: 'array' });
            const worksheet = workbook.Sheets[workbook.SheetNames[0]];
            csvContent = XLSX.utils.sheet_to_csv(worksheet);
        } else {
            csvContent = new TextDecoder('utf-8').decode(fileBuffer);
        }

        if (!csvContent.trim()) throw new Error("Arquivo vazio ou sem dados processáveis");
        onFileUpload(csvContent, file.name, file);
    } catch (error: any) {
        alert(`Erro ao ler arquivo: ${error.message}`);
    } finally {
        setIsParsing(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!disabled && !isParsing) {
      fileInputRef.current?.click();
    }
  };

  if (isUploaded) {
    return (
      <div className="flex-shrink-0 flex items-center justify-between space-x-2 bg-emerald-50 border border-emerald-100 dark:bg-emerald-900/20 dark:border-emerald-800 text-emerald-700 dark:text-emerald-400 px-3 py-1.5 rounded-full shadow-sm animate-fade-in w-full sm:w-auto transition-all">
        <div className="flex items-center space-x-1.5 min-w-0">
            <CheckCircleIcon className="w-3.5 h-3.5 flex-shrink-0 text-emerald-500" />
            <span className="text-[10px] font-bold truncate max-w-[100px]">{uploadedFileName}</span>
        </div>
        {onDelete && (
            <button
                type="button"
                onClick={onDelete}
                className="p-0.5 rounded-full hover:bg-emerald-200 dark:hover:bg-emerald-800 text-emerald-600 dark:text-emerald-400 transition-colors"
            >
                <XMarkIcon className="w-3 h-3" />
            </button>
        )}
      </div>
    );
  }

  return (
    <div className="flex-shrink-0">
      <input
        type="file"
        id={id}
        ref={fileInputRef}
        className="hidden"
        onChange={handleFileChange}
        disabled={disabled || isParsing}
        accept=".csv,.txt,.xlsx,.xls,.pdf,.docx"
      />
      <button
        type="button"
        onClick={handleClick}
        disabled={disabled || isParsing}
        className={`
          group inline-flex items-center justify-center space-x-1.5 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wide transition-all duration-300 relative overflow-hidden
          ${disabled 
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200 dark:bg-slate-800 dark:border-slate-700' 
              : 'text-white bg-gradient-to-r from-emerald-600 to-teal-500 hover:from-emerald-500 hover:to-teal-400 shadow-sm hover:shadow-emerald-500/30 hover:-translate-y-0.5 active:translate-y-0 active:scale-[0.98]'
          }
        `}
      >
         {isParsing ? (
           <>
              <svg className="animate-spin h-3 w-3 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
              <span className="tracking-wide">Processando...</span>
          </>
         ) : (
          <>
              <UploadIcon className="w-3 h-3 opacity-90" />
              <span className="tracking-wide relative z-10">{title}</span>
          </>
         )}
      </button>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger, Metrics } from './monitoringService';

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Utilitário de re-tentativa com backoff exponencial para respeitar limites de cota
 */
async function callWithRetry(fn: () => Promise<any>, retries = 3, delay = 3000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const errorMessage = error?.message?.toLowerCase() || "";
        // Detecta 429 (Rate Limit) ou 403 (Quota Exceeded)
        const isQuotaError = errorMessage.includes("429") || errorMessage.includes("quota") || errorMessage.includes("limit") || errorMessage.includes("403");

        if (retries > 0 && isQuotaError) {
            console.warn(`[IA] Limite atingido. Tentando novamente em ${delay}ms...`);
            await new Promise(r => setTimeout(r, delay));
            return callWithRetry(fn, retries - 1, delay * 2);
        }
        throw error;
    }
}

/**
 * INFERÊNCIA INICIAL: Usa o modelo Flash (Alta cota de requisições)
 * Ideal para processar centenas de linhas sem estourar o limite de custo/cota.
 */
export const performInitialInference = async (rawRows: string[][]): Promise<any[]> => {
    const ai = getAIClient();
    const indexedRows = rawRows.map((row, index) => ({ originalIndex: index, data: row }));

    const instructions = `
        VOCÊ É UM EXTRATOR FINANCEIRO VELOZ E PRECISO.
        FOCO: Transformar linhas de PDF/CSV em dados estruturados.

        REGRAS DE OURO:
        1. FLUXO CONTÍNUO: Ignore quebras de página, cabeçalhos repetidos e rodapés.
        2. ANCORAGEM: O "originalIndex" deve ser devolvido exatamente como recebido.
        3. LIMPEZA: Se a linha não for uma transação (for saldo ou título), retorne campos vazios.

        FORMATO:
        - date: YYYY-MM-DD
        - name: Nome/Descrição limpa.
        - amount: Valor numérico puro (ponto para decimal). Negativo para saídas.
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash para evitar erros de cota em massa
            contents: `Mapeie: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

/**
 * MOTOR DE APRENDIZADO: Usa o modelo Pro (Máxima inteligência)
 * Usado apenas após correções manuais para garantir que o padrão seja aprendido com perfeição.
 */
export const learnAndTransformFile = async (
    rawRows: string[][],
    manualCorrections: Array<{ originalRow: string[], corrected: { date: string, name: string, amount: string } }>
): Promise<any[]> => {
    const ai = getAIClient();

    const indexedRows = rawRows.map((row, index) => ({ 
        originalIndex: index, 
        content: row 
    }));

    const examplesPrompt = manualCorrections.map((ex, i) => `
        EXEMPLO REAL #${i + 1}:
        ENTRADA: ${JSON.stringify(ex.originalRow)}
        CORREÇÃO DO USUÁRIO: Data="${ex.corrected.date}", Nome="${ex.corrected.name}", Valor="${ex.corrected.amount}"
    `).join('\n');

    const instructions = `
        VOCÊ É O CÉREBRO DE APRENDIZADO DA PLATAFORMA.
        Sua missão é entender onde o usuário encontrou os dados nos exemplos e aplicar ao resto do arquivo.

        ATENÇÃO: O arquivo é um PDF longo. Ignore ruídos entre páginas.
        Mantenha a fidelidade absoluta aos índices fornecidos.

        EXEMPLOS PARA TREINAMENTO:
        ${examplesPrompt}
    `;

    return callWithRetry(async () => {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', // Pro para o treinamento ser infalível
            contents: `Aplique o aprendizado nestas linhas: ${JSON.stringify(indexedRows)}`,
            config: {
                systemInstruction: instructions,
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            name: { type: Type.STRING },
                            amount: { type: Type.STRING },
                            originalIndex: { type: Type.INTEGER }
                        },
                        required: ["date", "name", "amount", "originalIndex"]
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : [];
    });
};

export const getAISuggestion = async (
  transaction: Transaction,
  contributors: Contributor[]
): Promise<string> => {
  const ai = getAIClient();
  const contributorNames = contributors.map(c => c.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Sugira o contribuinte para: "${transaction.description}" em [${contributorNames}].`,
      config: { temperature: 0 }
    });
    return response.text?.trim() || "Nenhuma sugestão clara";
  } catch (error) {
    Logger.error("Error calling Gemini suggestion", error);
    return "Erro IA.";
  }
};

