                                                <td className={`text-center font-mono text-[10px] font-bold py-2 border-r ${referenceRowIdx === idx ? 'bg-indigo-600 text-white' : 'text-slate-400 bg-slate-50'}`}>{idx + 1}</td>
                                                {row.map((cell, cIdx) => <td key={cIdx} className="px-3 py-2 border-r border-slate-100 whitespace-nowrap text-slate-500">{cell || '---'}</td>)}
                                            </tr>
                                        ))}</tbody>
                                </table>
                            )}
                        </div>
                    </div>
                    <div className="basis-1/2 shrink-0 flex flex-col bg-white dark:bg-slate-900 shadow-[-10px_0_30px_rgba(0,0,0,0.05)] relative z-20 min-w-0">
                        <div className="px-8 py-3 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 flex flex-col shrink-0">
                            <div className="flex items-center justify-between mb-2">
                                <div className="flex items-center gap-2"><AdjustmentsHorizontalIcon className="w-4 h-4 text-emerald-500" /><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">IA: Extração e Purificação</span></div>
                                <button onClick={handleApplyReference} disabled={isAILoading} className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">{isAILoading ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <SparklesIcon className="w-4 h-4" />} Treinar Motor</button>
                            </div>
                            {isAILoading && (
                                <div className="flex flex-col gap-1 mt-1 animate-fade-in">
                                    <div className="flex justify-between items-center text-[9px] font-black text-indigo-600 uppercase tracking-tighter">
