                                        <span>{progress.current} de {progress.total}</span>
                                    </div>
                                    <div className="h-1 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${(progress.current/progress.total)*100}%` }}></div></div>
                                </div>
                            )}
                        </div>
                        <div ref={rightScrollRef} className="flex-1 overflow-auto custom-scrollbar">
                            <table className="w-full text-xs border-collapse">
                                <thead className="sticky top-0 z-20 bg-slate-50 dark:bg-slate-900 border-b"><tr><th className="px-6 py-4 text-left w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th><th className="px-6 py-4 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Identificação</th><th className="px-6 py-4 text-right w-32 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th><th className="px-6 py-4 w-12 text-center">Ações</th></tr></thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">{paginatedRows.map((row) => (
                                            <tr key={row.id} className={`h-[48px] group transition-all ${referenceRowIdx === row.originalIndex ? 'bg-indigo-50/70 dark:bg-indigo-900/10' : ''}`}>
                                                <td className="px-6 py-0">{row.status === 'processing' ? <div className="w-16 h-3 bg-slate-100 animate-pulse rounded"></div> : <input type="text" value={formatToBRDate(row.date)} onChange={(e) => updateRow(row.id, 'date', parseFromBRDate(e.target.value))} className="w-full bg-transparent border-none outline-none font-mono text-[11px] font-bold text-slate-600 dark:text-slate-400" />}</td>
                                                <td className="px-6 py-0 flex items-center gap-2">{row.status === 'processing' ? <div className="flex-1 h-3 bg-slate-100 animate-pulse rounded"></div> : <input type="text" value={row.name} onChange={(e) => updateRow(row.id, 'name', e.target.value)} className="w-full bg-transparent border-none outline-none text-[12px] font-black text-slate-900 dark:text-white" />}</td>
                                                <td className="px-6 py-0 text-right">{row.status === 'processing' ? <div className="w-12 h-3 bg-slate-100 animate-pulse rounded ml-auto"></div> : <input type="text" value={formatToBRAmount(row.amount)} onChange={(e) => updateRow(row.id, 'amount', parseFromBRAmount(e.target.value))} className={`w-full bg-transparent border-none outline-none text-right font-mono text-[12px] font-black ${parseFloat(row.amount) < 0 ? 'text-red-600' : 'text-emerald-600'}`} />}</td>
                                                <td className="px-4 py-0 text-center"><button onClick={() => updateRow(row.id, 'status', 'deleted')} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><TrashIcon className="w-4 h-4" /></button></td>
                                            </tr>
